export const QB: Question[] = [
  {id:"S1Q1",s:1,d:1,q:"Дані продакшену показують: у 12% випадків агент пропускає get_customer і викликає lookup_order лише за іменем клієнта, що інколи призводить до помилкової ідентифікації акаунта й неправильних повернень. Яка зміна найефективніше вирішить цю проблему надійності?",opts:["Додати programmatic prerequisite, що блокує lookup_order і process_refund до верифікованого customer ID","Підсилити system prompt вимогою обов'язкової верифікації через get_customer перед операціями із замовленнями","Додати few-shot приклади, де агент завжди першим викликає get_customer навіть за наявності номера замовлення","Впровадити routing-класифікатор, що вмикає лише підмножину інструментів під конкретний тип запиту"],a:0,ex:"Коли критична бізнес-логіка вимагає певної послідовності (верифікація перед поверненням коштів), programmatic enforcement дає детерміновані гарантії: він блокує lookup_order і process_refund, доки get_customer не поверне верифікований customer ID. Prompt-підходи — підсилення system prompt чи few-shot приклади з пріоритетом get_customer — лишаються ймовірнісними й мають ненульову ймовірність недотримання. Routing-класифікатор вирішує доступність інструментів, а не їх обов'язковий порядок виконання."},
  {id:"S1Q2",s:1,d:2,q:"Логи показують, що агент часто кличе get_customer на запити про замовлення (напр. «перевір моє замовлення #12345») замість lookup_order. Обидва інструменти мають мінімальні описи («Retrieves customer information» / «Retrieves order details») і приймають схожі формати ідентифікаторів. Який найефективніший перший крок?",opts:["Розширити опис кожного інструмента: очікувані формати входу, приклади запитів, edge cases і чіткі межі застосування","Додати 5–8 ретельних few-shot прикладів у system prompt, що скеровують order-запити саме на lookup_order","Реалізувати окремий routing-шар, що парсить ввід і наперед обирає інструмент за ключовими словами","Об'єднати обидва інструменти в один lookup_entity, що сам визначає потрібний бекенд за вводом"],a:0,ex:"Описи інструментів — основний механізм вибору для LLM. За мінімальних описів моделі бракує контексту, щоб розрізнити схожі інструменти; розширення опису форматами входу, прикладами запитів, edge cases і межами застосування б'є прямо в причину. Few-shot приклади додають токени, не усуваючи її. Окремий routing-шар з парсингом ключових слів — over-engineering, що обходить розуміння моделі. Злиття в lookup_entity — валідна, але важча архітектурна зміна, ніж потрібно для «першого кроку»."},
  {id:"S1Q3",s:1,d:5,q:"Агент дає лише 55% first-contact resolution при цілі 80%. Логи показують: він ескалює прості кейси (стандартні заміни з фото-доказом), але намагається сам обробляти складні ситуації з винятками з політики. Як найкраще покращити калібрування ескалації?",opts:["Додати у system prompt явні критерії ескалації з прикладами «коли ескалювати, а коли вирішувати»","Просити агента самооцінювати власну confidence за шкалою 1–10 і слати до людини нижче заданого порогу","Розгорнути окрему classifier-модель на історичних тікетах, що передбачає потребу в ескалації кейсу","Додати sentiment-аналіз вхідних повідомлень і ескалювати при перевищенні порогу негативного тону клієнта"],a:0,ex:"Корінь проблеми — нечіткі межі рішення; явні критерії ескалації з few-shot прикладами «коли ескалювати, а коли вирішувати самостійно» б'ють прямо в нього і є пропорційним першим кроком. Самооцінка confidence погано калібрована — агент уже впевнений саме на складних кейсах, тож поріг не спрацює. Окрема classifier-модель — over-engineering для першого кроку. Sentiment-аналіз вирішує іншу проблему: негативний тон не корелює зі складністю кейсу чи винятками з політики."},
  {id:"S1Q4",s:1,d:1,q:"Політика вимагає, щоб повернення понад $500 НІКОЛИ не виконувались автоматично, а йшли на людину. Зараз ця вимога описана в system prompt, але зрідка порушується. Що дасть детерміновану гарантію?",opts:["Hook, що перехоплює виклик process_refund і програмно блокує суми понад $500, віддаючи їх на escalate_to_human","Чіткіше формулювання в system prompt із капіталізованим жирним NEVER і повтором правила про ліміт у $500","Few-shot приклади, що демонструють відмову від автоматичних повернень на суми, які перевищують $500","Зниження temperature моделі, щоб вона суворіше й стабільніше дотримувалась інструкцій system prompt"],a:0,ex:"Коли бізнес-правило вимагає гарантованого дотримання на фінансово значущих діях, обирають hook з tool-call interception: він перехоплює вихідний виклик process_refund, блокує суми понад $500 і перенаправляє на escalate_to_human. Prompt-based підходи — капіталізований NEVER, few-shot приклади відмов чи зниження temperature — усі лишаються ймовірнісними й мають ненульовий рівень збоїв, тож не дають детермінованої гарантії на повернення понад поріг."},
  {id:"S1Q5",s:1,d:2,q:"Усі MCP-інструменти повертають при збої однаковий рядок «Operation failed». Через це агент однаково реагує і на таймаут, і на порушення політики, і на невалідний ввід. Як це виправити?",opts:["Повертати структуровані метадані: errorCategory, isRetryable і людиночитний опис","Додати у system prompt інструкцію завжди автоматично повторювати спробу при збої","Логувати помилки на бекенді детальніше, лишивши агенту той самий загальний рядок","Підвищити timeout усіх інструментів, щоб технічні помилки траплялись помітно рідше"],a:0,ex:"Уніфіковані помилки не дають агенту приймати правильні рішення про відновлення. Структуровані метадані — категорія transient/validation/permission, ознака isRetryable і людиночитний опис — дозволяють ретраїти transient-збої, пояснювати business-помилки клієнту й не марнувати спроби на non-retryable. Інструкція завжди ретраїти небезпечно повторює навіть невідновлювані дії. Детальніше логування на бекенді чи вищий timeout не міняють того загального рядка, який бачить сам агент."},
  {id:"S1Q6",s:1,d:5,q:"lookup_order повертає 40+ полів на замовлення, з яких для типового кейсу повернення релевантні лише ~5. У довгих діалогах ці виводи накопичуються й з'їдають контекст. Який підхід найкращий?",opts:["Обрізати verbose-виводи інструмента до релевантних полів ще до того, як вони потраплять у контекст","Збільшити max_tokens моделі, щоб вона спокійно вмістила всі 40+ полів кожного замовлення в діалозі","Періодично робити progressive summarization усієї історії діалогу разом із виводами замовлень у ній","Вимкнути lookup_order і просити клієнта диктувати потрібні деталі замовлення вручну в повідомленні"],a:0,ex:"Виводи інструментів накопичуються й споживають токени непропорційно до релевантності, коли з 40+ полів реально потрібні ~5. Тримання лише потрібних полів ще до потрапляння в контекст — пряме рішення. Збільшення max_tokens стосується довжини відповіді, а не контекст-вікна. Агресивна progressive summarization усієї історії ризикує згорнути точні числа й дати. Вимкнення lookup_order і ручна диктовка деталей помітно погіршують UX."},
  {id:"S1Q7",s:1,d:5,q:"get_customer повертає кількох клієнтів, що збігаються за наданим іменем. Як агенту коректно вчинити?",opts:["Попросити додатковий ідентифікатор (email, номер замовлення), а не обирати збіг за евристикою","Обрати найновіший за датою створення акаунт як найбільш імовірний відповідно до контексту запиту","Обрати акаунт із найбільшою кількістю замовлень як того клієнта, що найчастіше звертається до підтримки","Об'єднати всі знайдені збіги в один зведений профіль і продовжити обробку звернення на його основі"],a:0,ex:"Кілька збігів за іменем вимагають уточнення — запиту додаткового ідентифікатора на кшталт email чи номера замовлення, а не евристичного вибору. Будь-яка евристика (найновіший акаунт, акаунт із найбільшою кількістю замовлень) чи злиття збігів у єдиний профіль веде до помилкової ідентифікації й неправильних дій із чужим акаунтом, що особливо небезпечно для повернень коштів."},
  {id:"S1Q8",s:1,d:1,q:"Клієнт пише одним повідомленням одразу про три речі: повернення коштів за пошкоджений товар, зміну адреси доставки та скаргу на затримку. Яка стратегія обробки найкраща?",opts:["Декомпозувати звернення на окремі concern'и, паралельно дослідити кожен на спільному контексті й синтезувати єдину відповідь","Обробити лише перше питання про повернення коштів, а решту попросити надіслати окремими зверненнями пізніше","Ескалювати все звернення на живого оператора, бо багатоскладові запити лежать поза межами компетенції агента","Відповісти загальними формулюваннями без виклику жодних інструментів, щоб не плутати контексти трьох тем"],a:0,ex:"Багатоскладові звернення декомпозують на окремі concern'и (повернення, зміна адреси, скарга), досліджують кожен на спільному контексті — за потреби паралельно — і зводять у єдину резолюцію. Обробка лише першого питання губить частину запиту. Ескалація всього на людину зайва, бо кожен item у межах можливостей агента. Загальна відповідь без інструментів не вирішує жодного з конкретних питань клієнта."},
  {id:"S1Q9",s:1,d:5,q:"На початку діалогу клієнт прямо й однозначно вимагає з'єднати його з живим оператором. Як вчинити агенту?",opts:["Виконати ескалацію негайно, без спроби спершу самостійно розслідувати кейс клієнта","Спершу спробувати вирішити питання самому, і лише якщо не вдасться — тоді ескалювати на оператора","Запитати причину вимоги й переконати клієнта, що агент цілком здатен розв'язати його питання сам","Підняти confidence-поріг для цього діалогу й продовжити обробляти звернення автономно без людини"],a:0,ex:"Явну й однозначну вимогу клієнта про живого оператора виконують негайно, без спроб спершу розслідувати кейс. Це відрізняється від ситуації, де питання просте — там можна запропонувати вирішити, ескалюючи лише якщо клієнт наполягає. Спроба вирішити самому всупереч прямій вимозі, переконування клієнта чи продовження автономно ігнорують явно висловлене бажання й псують досвід."},
  {id:"S1Q10",s:1,d:1,q:"Різні MCP-інструменти повертають дати в різних форматах: get_customer — Unix timestamp, lookup_order — ISO 8601, а статус — числовим кодом. Це плутає модель при міркуванні. Який механізм найкращий для нормалізації?",opts:["PostToolUse hook, що перехоплює виводи інструментів і нормалізує всі формати дат до єдиного вигляду ще до обробки моделлю","Інструкція в system prompt самостійно конвертувати всі формати дат до єдиного вигляду під час міркування","Окремий subagent, що перехоплює й переписує кожну відповідь інструмента, приводячи дати до спільного формату","Few-shot приклади з різними форматами дат (Unix timestamp, ISO 8601, числовий код) і їх правильним трактуванням"],a:0,ex:"PostToolUse hook перехоплює результати інструментів і трансформує їх — нормалізує Unix timestamp, ISO 8601 і числові коди статусу до єдиного формату — до обробки моделлю, що дає детерміновану нормалізацію. Інструкція в system prompt і few-shot приклади лишаються ймовірнісними: модель може помилитись у конвертації. Окремий subagent для переписування кожної відповіді інструмента — надлишкова архітектура для суто механічної нормалізації форматів."},
  {id:"S1Q11",s:1,d:5,q:"У довгих діалогах ви робите progressive summarization історії. Згодом помічаєте, що агент «забуває» точну суму повернення, дату покупки й обіцянки, дані клієнту. Як це виправити?",opts:["Витягувати транзакційні факти в окремий persistent «case facts» блок, що додається в кожен промпт","Повністю відмовитись від сумаризації й завжди надсилати моделі всю історію діалогу без скорочень","Сумаризувати історію ще агресивніше, щоб лишалось більше місця в контексті під нові факти й репліки","Зберігати точні транзакційні факти лише в системі логування на бекенді, поза контекстом самої моделі"],a:0,ex:"Ризик progressive summarization — згортання чисел, відсотків, дат і обіцянок клієнту в розмиті формулювання. Рішення — тримати точні транзакційні факти (суми повернень, дати покупки, номери замовлень, статуси) в окремому persistent «case facts» блоці, що додається в кожен промпт поза сумаризованою історією. Повна відмова від сумаризації нереалістична за токенами; агресивніша сумаризація погіршує проблему; факти лише в бекенд-логах не доходять до моделі."},
  {id:"S1Q12",s:1,d:1,q:"Ви реалізуєте agentic loop. Що має визначати, продовжувати виконувати інструменти чи завершити й показати фінальну відповідь?",opts:["Поле stop_reason у відповіді API визначає наступний крок циклу виконання","Наявність будь-якого тексту в assistant-повідомленні як сигнал завершити цикл","Фіксований ліміт ітерацій як основний механізм зупинки роботи агента","Парсинг natural-language фраз на кшталт «Done» чи «Завершено» у відповіді"],a:0,ex:"Керування agentic loop будують на полі stop_reason: значення «tool_use» означає виконати інструмент і продовжити цикл, а «end_turn» — завершити й показати фінальну відповідь. Решта підходів — anti-patterns: перевірка наявності тексту хибна, бо модель часто додає текст разом із tool_use; жорсткий ліміт ітерацій обриває валідну роботу; парсинг natural-language сигналів ненадійний через варіативність формулювань."},
  {id:"S1Q13",s:1,d:2,q:"process_refund відхиляє запит, бо сума перевищує ліміт політики (бізнес-правило, не технічний збій). Що інструмент має повернути, щоб агент відреагував коректно?",opts:["Структуровану помилку isError з retriable:false і клієнт-дружнім поясненням причини","Той самий формат, що й для технічного таймауту, аби агент повторив виклик ще раз","Порожній успішний результат без позначки помилки, щоб зайвий раз не турбувати клієнта","Голий HTTP 500 без категорії помилки, прапора retriable чи опису її причини знову"],a:0,ex:"Порушення бізнес-правила (перевищення ліміту суми) слід позначати isError з retriable:false і додавати зрозуміле для клієнта пояснення причини відмови — тоді агент комунікує коректно й не марнує спроби на ретраї. Формат таймауту спровокує зайві повтори ідентичного виклику; порожній успіх приховує помилку й вводить агента в оману; голий 500 без метаданих не дає контексту для правильної реакції."},
  {id:"S1Q14",s:1,d:5,q:"Клієнт просить price-match під ціну конкурента. Політика описує лише коригування під власні попередні ціни магазину й нічого не каже про конкурентів. Що має зробити агент?",opts:["Ескалювати запит, бо політика мовчить і неоднозначна щодо цього кейсу","Відмовити клієнту за принципом «якщо ніде не написано — значить заборонено»","Погодити price-match самостійно, спираючись на відсутність явної заборони","Вигадати власний розумний відсоток знижки як компромісне рішення на місці"],a:0,ex:"Коли політика неоднозначна або взагалі мовчить щодо конкретного запиту (price-match під ціну конкурента відсутній — є лише власні попередні ціни магазину), це policy gap і прямий тригер ескалації, а не просто складність кейсу. Самостійні рішення — відмова, погодження чи вигадана знижка — ризикують суперечити майбутній офіційній політиці й створюють непослідовність у обслуговуванні."},
  {id:"S1Q15",s:1,d:1,q:"Колега пропонує завершувати agentic loop, коли модель згенерувала текстову відповідь без виклику інструмента, АБО після 10 ітерацій «про всяк випадок». Чому це проблема?",opts:["Це anti-patterns: і перевірка тексту, і жорсткий ліміт ітерацій ненадійні","Проблеми немає — це стандартний рекомендований підхід до зупинки циклу","Проблема лише в значенні ліміту: з порогом 50 замість 10 підхід стає коректним","Текст треба парсити регулярками на ключові слова — лише тоді зупинка надійна"],a:0,ex:"Перевірка наявності тексту, ліміт ітерацій як основний стоп-механізм і парсинг natural-language — класичні anti-patterns: модель часто додає текст разом із tool_use, а фіксований ліміт обриває валідну роботу. Коректне завершення базують на stop_reason == «end_turn». Зміна порогу ітерацій не усуває хибності самого механізму, а регулярки по ключових словах лишаються крихкими до формулювань."},
  {id:"S1Q16",s:1,d:2,q:"Команда поступово дала агенту 18 інструментів. Тепер він почав плутатись у виборі й інколи бере не той інструмент. Який принцип допоможе найбільше?",opts:["Звузити набір до 4–5 інструментів, релевантних саме ролі цього агента","Додати ще інструментів-«хелперів», щоб завжди був точний інструмент під кейс","Перейменувати всі 18 наявних інструментів у коротші й лаконічніші назви","Завжди форсувати tool_choice на перший інструмент у списку доступних"],a:0,ex:"Завелика кількість інструментів (18 замість 4–5) деградує надійність вибору, бо зростає складність рішення для моделі — звуження набору під конкретну роль агента б'є прямо в причину. Додавання ще інструментів лише погіршує перевантаження; перейменування не міняє їх кількості й складності вибору; форсування першого через tool_choice ламає здатність агента обирати доречний інструмент під контекст."},
  {id:"S2Q1",s:2,d:3,q:"Ви хочете створити custom-команду /review, що запускає стандартний чек-лист код-рев'ю команди. Вона має бути доступна кожному розробнику після clone/pull репозиторію. Де створити файл команди?",opts:["У директорії .claude/commands/ у репозиторії проєкту, щоб вона версіонувалась","У ~/.claude/commands/ у домашній директорії кожного окремого розробника команди","У файлі CLAUDE.md у корені проєкту, оформивши її як окрему секцію команд","У .claude/config.json у масиві commands разом з описом кожної доступної команди"],a:0,ex:"Project-scoped slash-команди зберігають у .claude/commands/ репозиторію — вони версіонуються разом із кодом і доступні всім після clone/pull. Розміщення в ~/.claude/commands/ робить команду особистою й не шерить її між розробниками; CLAUDE.md призначений для контексту, а не для виконуваних команд; а .claude/config.json з масивом commands описує неіснуючий у Claude Code механізм."},
  {id:"S2Q2",s:2,d:3,q:"Вам доручили реструктуризувати моноліт у мікросервіси: зміни в десятках файлів і рішення про межі сервісів та залежності модулів. Який підхід обрати?",opts:["Увійти в plan mode: дослідити кодбазу, зрозуміти залежності й спроєктувати підхід","Почати з direct execution й міняти інкрементально, дозволивши реалізації виявити межі","Direct execution із повними наперед інструкціями, як структурувати кожен сервіс","Почати в direct execution і перемкнутись у plan mode лише за несподіваної складності"],a:0,ex:"Plan mode створений саме для масштабних змін у десятках файлів, кількох валідних підходів та архітектурних рішень про межі сервісів і залежності модулів — він дозволяє безпечно дослідити код перед комітом до змін. Інкрементальний direct execution ризикує дорогими переробками, коли межі виявляться невдалими; підхід із повними наперед інструкціями хибно припускає готову відповідь без дослідження; а відкладене перемикання ігнорує, що складність уже задана самими вимогами."},
  {id:"S2Q3",s:2,d:3,q:"Ви фіксите один баг у єдиному файлі з чітким stack trace, що прямо вказує на місце. Який режим оптимальний?",opts:["Direct execution — зміна добре зрозуміла, чітко обмежена за scope і має точне місце","Plan mode — будь-яка зміна коду потребує попереднього формального планування","Plan mode із залученням Explore subagent для повного аналізу всієї кодбази","Спершу fork_session для ізоляції, потім direct execution у новій сесії"],a:0,ex:"Для простих, добре окреслених змін (single-file fix з чітким stack trace, що прямо вказує на місце) пасує direct execution. Plan mode потрібен для архітектурних або багатофайлових задач, тож вимагати його для будь-якої зміни коду — надлишково; залучення Explore subagent для аналізу всієї кодбази тут марнує контекст; а fork сесії додає зайвий крок ізоляції без потреби."},
  {id:"S2Q4",s:2,d:3,q:"Новий член команди скаржиться, що Claude Code не застосовує командні інструкції, які працюють у всіх інших. Ви з'ясовуєте, що інструкції лежать у ~/.claude/CLAUDE.md одного з інженерів. У чому причина й виправлення?",opts:["User-level конфіг (~/.claude/CLAUDE.md) не шериться через VCS; перенести в project-level","Це баг кешу конфігурації; новому інженеру варто просто перевстановити сам Claude Code","Інструкції треба вручну продублювати в кожному окремому ~/.claude/CLAUDE.md для всіх колег","Перенести інструкції у .gitignore, щоб вони згодом підхопились усіма геть автоматично"],a:0,ex:"Налаштування user-level (~/.claude/CLAUDE.md) застосовуються лише до конкретного користувача й не передаються через version control, тому інструкції одного інженера не діють у решти. Командні стандарти мають бути project-level (.claude/CLAUDE.md або кореневий CLAUDE.md), щоб версіонуватись і діяти на всіх. Це не проблема кешу; ручне дублювання по домашніх теках некероване й розсинхронізується; а .gitignore узагалі виключає файл із репозиторію, замість того щоб його шерити."},
  {id:"S2Q5",s:2,d:3,q:"Ваш CLAUDE.md розрісся до сотень рядків і став важко підтримуваним. Який підхід рекомендований для модульності?",opts:["Розбити на тематичні файли (testing, deployment) і підключати через @import","Стиснути файл, видаливши коментарі, зайві пробіли й усі порожні рядки для компактності","Перенести весь наявний вміст у єдиний гігантський system prompt поза самим CLAUDE.md","Створити по копії повного CLAUDE.md у кожній окремій піддиректорії всього проєкту"],a:0,ex:"Великий CLAUDE.md дробиться на тематичні файли (наприклад, testing.md, api-conventions.md, deployment.md) і підключається через @import-синтаксис — це дає модульність і легку підтримку. Просте стиснення прибиранням пробілів не вирішує проблему підтримуваності; зведення всього в єдиний system prompt лише концентрує той самий моноліт; а копії повного файлу в кожній теці створюють розсинхронізацію й дублювання."},
  {id:"S2Q6",s:2,d:3,q:"Ви прозою описуєте бажану трансформацію коду, але Claude інтерпретує її щоразу по-різному. Що найефективніше комунікує очікування?",opts:["Надати 2–3 конкретні приклади пар вхід/вихід, що однозначно демонструють трансформацію","Переписати інструкцію ще детальнішою прозою з більшою кількістю прикметників","Підвищити max_tokens, щоб модель докладніше пояснювала кожен крок трансформації","Додати в кінці інструкції чітку фразу «будь дуже точним» для більшої суворості"],a:0,ex:"Коли прозовий опис трансформації трактується щоразу по-різному, найдієвіше — кілька конкретних прикладів вхід/вихід (few-shot), які однозначно показують потрібний результат і прибирають неоднозначність. Ще детальніша проза з прикметниками не усуває різночитання; підвищення max_tokens впливає на довжину виводу, а не на консистентність трансформації; а заклик «будь точним» не дає моделі конкретного орієнтира поведінки."},
  {id:"S2Q7",s:2,d:5,q:"Під час тривалої сесії дослідження великої кодбази Claude починає давати непослідовні відповіді й посилатися на «типові патерни» замість конкретних класів, знайдених раніше. Як протидіяти цій деградації контексту?",opts:["Вести scratchpad-файл із ключовими знахідками й звертатись до нього у нових питаннях","Перезапускати сесію повністю з нуля при кожному наступному новому питанні до цієї кодбази","Підвищити temperature, щоб відповіді стали різноманітнішими, ширшими й нібито точнішими","Ігнорувати — для довгих дослідницьких сесій це начебто очікувана нормальна поведінка"],a:0,ex:"У розширених сесіях контекст деградує: модель «зісковзує» на типові патерни замість конкретних класів, знайдених раніше. Зовнішній scratchpad-файл із ключовими знахідками, на який агент спирається в наступних питаннях, фіксує конкретику поза розмовою й компенсує цю деградацію. Повний рестарт щоразу втрачає накопичений прогрес; підвищення temperature лише збільшує розкид відповідей; а ігнорування лишає проблему невирішеною."},
  {id:"S2Q8",s:2,d:3,q:"Ви реалізуєте кешування у незнайомому домені й не впевнені, які грані врахували. Який прийом найкраще виявить непомічені міркування ще до реалізації?",opts:["Interview pattern: попросити Claude поставити вам запитання, що піднімуть рішення","Одразу попросити повну реалізацію й виправляти баги вже по факту їх поступової появи","Дати лише прозовий опис задачі й цілком покластися на дефолтні рішення самої моделі","Згенерувати код двічі різними промптами й обрати з них довшу та детальнішу версію"],a:0,ex:"Interview pattern — коли Claude ставить вам запитання, що виявляють непередбачені приховані міркування (стратегії інвалідації кешу, режими збоїв) ще до реалізації; це особливо цінно в незнайомому домені, де ви не впевнені, які грані врахували. Прохання одразу реалізувати пропускає етап виявлення й переносить помилки в дебаг; опора на дефолти моделі лишає приховані рішення непоміченими; а вибір довшої з двох генерацій не корелює з повнотою врахованих граней."},
  {id:"S2Q9",s:2,d:3,q:"У вас є skill для аналізу кодбази, що генерує дуже багатослівний вивід і засмічує основну розмову. Яка опція frontmatter це вирішує?",opts:["context: fork — запускає skill в ізольованому sub-agent контексті без забруднення розмови","allowed-tools: лише Read — обмежує інструменти й тим скорочує обсяг виводу самого skill","argument-hint — підказує параметри виклику й тим зменшує загальну багатослівність відповіді","model: haiku — менша дефолтна модель за замовчуванням повертає коротший і стисліший вивід"],a:0,ex:"Опція frontmatter context: fork ізолює skill у subagent-контексті, тож його багатослівний вивід не потрапляє в основну сесію — у головну розмову повертається лише результат. Обмеження інструментів через allowed-tools звужує доступ, а не ізолює контекст; argument-hint керує підказкою параметрів і не впливає на обсяг виводу; а зміна моделі не дає контекстної ізоляції, навіть якщо вивід стане коротшим."},
  {id:"S2Q10",s:2,d:5,q:"Під час тривалої багатофазної сесії контекст заповнюється багатослівним discovery-виводом, і ви бачите, що місця лишається все менше. Яка вбудована команда допоможе зменшити споживання контексту по ходу?",opts:["/compact — стискає накопичений контекст під час сесії, звільняючи місце","/reset — повністю очищає й обнуляє весь стан та контекст поточної сесії","/verbose — перемикає рівень деталізації виводу команд і інструментів","/tokens — показує поточний лічильник спожитих токенів контексту"],a:0,ex:"/compact зменшує споживання контексту у розширених сесіях, коли вікно заповнюється багатослівним discovery-виводом, стискаючи історію зі збереженням ключового. Повне очищення стану втратило б увесь прогрес багатофазної задачі; перемикання деталізації виводу не стискає вже накопичений контекст; а лічильник токенів лише показує цифру, нічого не звільняючи."},
  {id:"S2Q11",s:2,d:3,q:"Поведінка Claude Code різниться між сесіями, і ви підозрюєте, що десь не підвантажується потрібний memory-файл. Яка команда допоможе діагностувати, які memory-файли завантажені?",opts:["/memory — показує memory-файли, наразі завантажені в сесію","/debug — вмикає повний трейс виконання й внутрішніх викликів","/files — перелічує всі файли проєкту, що видимі для агента","/config — відкриває редактор глобального конфігу налаштувань"],a:0,ex:"Команда /memory показує, які memory-файли підвантажені в поточну сесію, тож нею можна діагностувати непослідовну поведінку між сесіями, коли підозра падає на непідхоплений файл. Трейс виконання не показує склад завантаженої пам'яті; перелік файлів проєкту не каже, що саме завантажено як memory; а редактор конфігу відкриває налаштування, а не стан підвантажених memory-файлів."},
  {id:"S2Q12",s:2,d:3,q:"Ви знайшли кілька дефектів у щойно згенерованому модулі. Частина з них взаємопов'язана (виправлення одного впливає на інші), частина — незалежна. Як подавати фідбек для ітерації?",opts:["Взаємопов'язані проблеми подавати разом одним повідомленням, а незалежні — окремими ітераціями","Завжди подавати геть усі знайдені проблеми одним великим повідомленням, незалежно від зв'язків між ними","Завжди виправляти строго по одній проблемі за раз, навіть якщо кілька дефектів очевидно пов'язані між собою","Подавати лише найкритичнішу проблему, а решту знайдених дефектів свідомо ігнорувати до наступного релізу"],a:0,ex:"Взаємодіючі проблеми краще адресувати в одному детальному повідомленні, бо їх виправлення взаємозалежні й модель має бачити повну картину одразу; незалежні ж проблеми ефективніше виправляти послідовно окремими ітераціями. Жорстке правило «завжди разом» ігнорує користь поетапності для незв'язаних дефектів; «завжди по одній» ламає координацію взаємозалежних виправлень; подавання лише найкритичнішого лишає реальні дефекти невиправленими."},
  {id:"S2Q13",s:2,d:3,q:"Ви хочете персональний варіант командного skill з іншою поведінкою, але так, щоб НЕ зачепити колег. Як це зробити?",opts:["Створити персональний варіант у user-level каталозі ~/.claude/skills/ під іншою назвою, не чіпаючи командний skill","Відредагувати спільний skill прямо в каталозі .claude/skills/ репозиторію проєкту під власну потребу","Закомітити власну версію skill поверх командної в .claude/skills/ репозиторію спільного командного проєкту","Видалити командний skill із .claude/skills/ і замінити його власною модифікованою реалізацією поведінки"],a:0,ex:"Персональні кастомізації роблять у user-level каталозі ~/.claude/skills/ під іншою назвою — це не шериться через version control і не впливає на команду. Редагування чи коміт у спільний project-level .claude/skills/ зачепить усіх колег, бо цей каталог версіонується; видалення командного skill тим паче ламає роботу всієї команди."},
  {id:"S2Q14",s:2,d:3,q:"У багатофазній задачі фаза discovery дає стільки виводу, що з'їдає контекст-вікно ще до реалізації. Який механізм Claude Code це ізолює?",opts:["Explore subagent — ізолює discovery й повертає в основну сесію лише стислий підсумок","Збільшення параметра max_tokens основної сесії, щоб у відповідь умістилося більше discovery","Запуск усієї багатофазної задачі в plan mode, без залучення жодних окремих subagent'ів","Тимчасове вимкнення інструментів Read і Grep на час фази discovery заради контексту"],a:0,ex:"Explore subagent ізолює verbose discovery-вивід у власному контексті й повертає в основну розмову лише стислий підсумок знахідок, зберігаючи контекст-вікно основної сесії. Збільшення max_tokens стосується довжини відповіді, а не розміру контекст-вікна; plan mode сам по собі планує, але не ізолює discovery в окремому контексті; вимкнення Read/Grep зробило б дослідження кодбази взагалі неможливим."},
  {id:"S2Q15",s:2,d:3,q:"Ви ітеративно доводите складну функцію до коректності. Який підхід найнадійніше скеровує прогресивне покращення?",opts:["Спершу написати тест-сьют з очікуваною поведінкою й edge cases, далі ітерувати, ділячись падіннями тестів","Просити Claude самостійно оцінювати готовність коду й зупиняти роботу на його власний суб'єктивний сигнал","Поступово збільшувати довжину промпта з кожною новою ітерацією, додаючи дедалі більше прозових вимог","Генерувати по п'ять різних варіантів реалізації на кожному кроці й щоразу обирати найкоротший із них"],a:0,ex:"Test-driven ітерація дає об'єктивний сигнал прогресу: спочатку тест-сьют, що покриває потрібну поведінку, edge cases і перформанс, далі ітерації через шерінг падінь тестів. Самооцінка готовності моделлю погано калібрована й суб'єктивна; нарощування довжини промпта чи вибір найкоротшого з кількох варіантів — довільні евристики без об'єктивного критерію коректності."},
  {id:"S2Q16",s:2,d:3,q:"Ви плануєте міграцію бібліотеки, що зачіпає 45+ файлів. Як найкраще поєднати режими роботи?",opts:["Plan mode для дослідження кодбази й вибору підходу до міграції, потім direct execution для виконання плану","Лише direct execution від самого початку й до кінця міграції, заради максимальної швидкості внесення змін","Лише plan mode — використовувати його і для планування підходу, і для безпосереднього внесення усіх правок","Окрема нова сесія Claude Code на кожен із 45 файлів, без жодного спільного наскрізного плану міграції"],a:0,ex:"Оптимально поєднати plan mode для розслідування залежностей і проєктування підходу з direct execution для реалізації вже спланованого — це класичний патерн для масштабних багатофайлових міграцій. Лише direct execution ризикує дорогими переробками; лише plan mode не вносить змін у код; роздроблені сесії на кожен файл втрачають цілісність плану й спільний контекст залежностей."},
  {id:"S3Q1",s:3,d:1,q:"Запустивши систему на темі «вплив AI на креативні індустрії», ви бачите: усі subagent'и відпрацювали успішно, але фінальні звіти охоплюють лише візуальне мистецтво й повністю пропускають музику, письменство та кіно. У логах coordinator'а: він розбив тему на «AI in digital art», «AI in graphic design», «AI in photography». Найімовірніша корінна причина?",opts:["Декомпозиція coordinator'а надто вузька — призначення не покривають усіх доменів самої теми","Synthesis-агенту бракує інструкцій виявляти прогалини покриття серед отриманих ним знахідок","Запити web-search агента надто вузькі, тож їх варто розширити для ширшого охоплення джерел","Document-аналіз агент відсіює не-візуальні джерела через надто жорсткі критерії релевантності"],a:0,ex:"Логи прямо показують причину: coordinator розклав «креативні індустрії» лише на візуальні підтеми (digital art, graphic design, photography), пропустивши музику, письменство й кіно, тож його призначення не покрили всіх релевантних доменів теми. Subagent'и коректно зробили те, що їм призначили в межах заданого scope. Решта варіантів помилково звинувачують нижчих агентів: брак gap-аналізу в synthesis, вузькість пошукових запитів чи жорсткий фільтр релевантності в document-аналізі — жоден з них не пояснює, чому non-visual домени взагалі не потрапили у призначення."},
  {id:"S3Q2",s:3,d:5,q:"Web-search subagent впадає в timeout на складній темі. Ви проєктуєте, як ця інформація про збій тече назад до coordinator'а. Який підхід до error propagation найкраще вмикає інтелектуальне відновлення?",opts:["Повернути coordinator'у структурований error-контекст: тип збою, пробуваний запит і partial results","Реалізувати retry з exponential backoff усередині subagent'а й повернути лише «search unavailable» по спробах","Перехопити timeout і повернути порожній результат, позначений як успішний, аби не зупиняти весь пайплайн","Прокинути timeout-виняток у top-level handler, що негайно завершує весь дослідницький research-воркфлоу"],a:0,ex:"Структурований error-контекст дає coordinator'у дані для розумного рішення: ретрай із модифікацією запиту, перехід на альтернативний підхід чи продовження з partial results. Загальний статус «search unavailable» після внутрішніх ретраїв ховає контекст і не дає coordinator'у вибору. Позначення збою як «успіх» приховує помилку (silent suppression). Завершення всього воркфлоу через один timeout надмірне й позбавляє систему стійкості."},
  {id:"S3Q3",s:3,d:2,q:"Synthesis-агент часто має перевіряти конкретні факти, повертаючи керування coordinator'у → web-search → знову synthesis (+2–3 round trips, +40% latency). 85% перевірок — прості факт-чеки (дати, імена, статистика), 15% — глибше дослідження. Як зменшити overhead, зберігши надійність?",opts:["Дати synthesis-агенту scoped-інструмент verify_fact для простих lookup'ів, а складні лишити через coordinator","Накопичувати всі потреби верифікації й одним батчем повертати їх coordinator'у вже наприкінці проходу синтезу","Дати synthesis-агенту повний необмежений доступ до всіх web-search інструментів для самостійної перевірки фактів","Web-search агент має проактивно кешувати додатковий контекст навколо кожного джерела «про запас» заздалегідь"],a:0,ex:"Принцип найменших привілеїв: scoped verify_fact покриває 85% простих факт-чеків (дати, імена, статистика) без round trips, а складні 15% лишаються в наявному патерні координації через coordinator. Батч наприкінці створює блокуючі залежності й затримує синтез. Повний доступ до web-search порушує separation of concerns і провокує misuse. Спекулятивний кеш не передбачить, які саме факти знадобляться, тож не дасть надійної економії."},
  {id:"S3Q4",s:3,d:1,q:"Synthesis-subagent видає звіти так, ніби не бачив знахідок web-search і document-агентів. Coordinator їх викликав, але synthesis «не знає» їхніх результатів. Найімовірніша причина?",opts:["Subagent'и не успадковують контекст автоматично — знахідки треба явно передавати у промпт synthesis-агента","Synthesis-агенту бракує доступу до інструмента Task, без якого він зовсім не бачить чужих результатів роботи","Координатор використовує застарілу версію SDK, що чомусь не прокидає контекст між окремими агентами системи","Потрібно підвищити max_tokens synthesis-агента, щоб він зміг умістити всі результати решти агентів одразу"],a:0,ex:"Subagent'и працюють з ізольованим контекстом і не успадковують історію coordinator'а; знахідки web-search і document-агентів треба явно вкладати у промпт synthesis-агента. Інструмент Task потрібен для спавну subagent'ів, а не для отримання чужих результатів. Версія SDK тут ні до чого — ізоляція контексту є дизайном, а не багом. Підвищення max_tokens впливає лише на довжину виводу, а не на те, чи дані взагалі потрапили у промпт."},
  {id:"S3Q5",s:3,d:1,q:"Coordinator має запустити трьох незалежних subagent'ів одночасно, щоб скоротити час. Як це зробити правильно?",opts:["Емітувати кілька викликів Task в одній відповіді coordinator'а задля паралельного одночасного старту всіх агентів","Викликати Task по одному в окремих ходах, чекаючи завершення кожного перед запуском наступного агента","Створити один subagent, що всередині послідовно виконає всі три окремі задачі за один спільний прохід","Підвищити temperature coordinator'а, щоб він охочіше запускав усіх трьох агентів геть одночасно тут"],a:0,ex:"Паралельний запуск роблять, емітуючи кілька викликів Task в одній відповіді coordinator'а — тоді subagent'и стартують одночасно. Послідовні виклики в окремих ходах із очікуванням кожного дають строго sequential виконання без виграшу в часі. Один subagent, що робить три задачі по черзі, теж не паралелить. Temperature керує варіативністю генерації й не впливає на конкурентність запуску."},
  {id:"S3Q6",s:3,d:1,q:"Coordinator-агент не може запустити жодного subagent'а — виклики просто не відбуваються. Що найімовірніше треба перевірити в його конфігурації?",opts:["Чи містить allowedTools інструмент «Task» — він обов'язковий для спавну subagent'ів","Чи увімкнено streaming у відповідях coordinator'а, без якого виклики начебто не відправляються","Чи однакова модель у coordinator'а й subagent'ів, бо інакше спавн нібито жорстко блокується","Чи достатній max_tokens coordinator'а, щоб умістити всі відповіді запущених subagent'ів"],a:0,ex:"Механізм спавну subagent'ів — інструмент Task; якщо його немає в allowedTools coordinator'а, виклики просто не відбуваються. Streaming впливає на спосіб доставки токенів, а не на можливість викликати інструмент. Збіг моделей coordinator'а й subagent'ів не є передумовою спавну — вони можуть відрізнятись. max_tokens обмежує довжину відповіді, але не блокує саму здатність викликати Task."},
  {id:"S3Q7",s:3,d:5,q:"Після кроку синтезу у фінальному звіті губиться, з якого саме джерела взято кожне твердження. Як зберегти провенанс через синтез?",opts:["Вимагати від subagent'ів структуровані claim-source мапінги, які synthesis зберігає й зливає у звіт","Додати в кінці звіту загальний список усіх джерел без прив'язки до конкретних тверджень","Просити synthesis-агента вгадувати ймовірне джерело кожного твердження за стилем тексту","Зберігати перелік джерел лише у логах на бекенді, а не в робочому контексті самих агентів"],a:0,ex:"Атрибуцію втрачають під час сумаризації, коли стискають без збереження зв'язку твердження з джерелом. Рішення — структуровані claim-source мапінги (URL чи назва документа й релевантний уривок), які subagent'и повертають, а downstream-агенти зберігають і зливають при синтезі. Загальний список без прив'язки, вгадування за стилем чи логи поза контекстом не зберігають провенанс на рівні тверджень."},
  {id:"S3Q8",s:3,d:5,q:"Два авторитетні джерела дають різну статистику по одному показнику. Як synthesis-агент має вчинити?",opts:["Зберегти обидва значення з атрибуцією джерел, явно позначивши конфлікт між цими даними","Обрати значення з того джерела, що було оброблене або просто згадане першим у вхідних даних","Усереднити два значення в одне підсумкове число, щоб подати читачу єдиний зведений показник","Відкинути обидва значення як ненадійні й узагалі не включати цей показник у фінальний звіт"],a:0,ex:"Конфліктні дані з авторитетних джерел анотують із зазначенням обох джерел і явним маркуванням розбіжності, а не обирають довільно. Вибір першого джерела довільний і приховує конфлікт. Усереднення вигадує число, якого немає в жодному джерелі, і маскує розбіжність. Відкидання обох значень втрачає валідну інформацію та залишає прогалину в покритті показника."},
  {id:"S3Q9",s:3,d:1,q:"Coordinator завжди проганяє повний пайплайн (усі subagent'и) навіть для простих запитів, що марнує час і токени. Як це покращити?",opts:["Проєктувати coordinator так, щоб він аналізував вимоги запиту й динамічно обирав, яких subagent'ів викликати","Прибрати coordinator і дозволити subagent'ам спілкуватися напряму між собою заради економії часу й токенів","Зробити всіх subagent'ів обов'язковими в кожному запиті, але ретельно оптимізувати кожного з них для швидкості","Кешувати раніше згенеровані відповіді й повертати їх на будь-який вхідний запит без повторного пайплайну"],a:0,ex:"Coordinator має аналізувати складність запиту й динамічно обирати лише потрібних subagent'ів, а не завжди гнати повний пайплайн. Прибирання coordinator'а ламає hub-and-spoke — втрачаються спостережуваність і централізована обробка помилок. Обов'язковість усіх subagent'ів лишає те саме марнування часу й токенів. Сліпий кеш повертає некоректні відповіді на запити, що відрізняються від закешованих."},
  {id:"S3Q10",s:3,d:5,q:"Synthesis позначає як «суперечність» дані, що насправді просто зібрані в різні роки. Як запобігти цьому хибному трактуванню?",opts:["Вимагати від subagent'ів включати дату публікації чи збору даних у структуровані виводи кожного разу","Завжди обирати найновіше число й ігнорувати всі старіші значення як безнадійно застарілі та зайві","Заборонити агентам використовувати будь-які числові дані, що можуть змінюватися з плином часу й контексту","Підвищити поріг розбіжності, за яким два значення взагалі починають вважатися суперечливими одне одному"],a:0,ex:"Темпоральні дані потребують дат публікації або збору в структурованих виводах, щоб різниця у часі вимірювання не трактувалась як суперечність. Сліпий вибір найновішого числа відкидає валідні історичні дані й не пояснює природу різниці. Повна відмова від числових даних знищує суть дослідницького звіту. Зміна порога розбіжності лише маскує симптом, не розрізняючи реальний конфлікт від темпоральної відмінності."},
  {id:"S3Q11",s:3,d:1,q:"Coordinator отримав синтез, у якому є очевидні прогалини покриття теми. Який патерн найкраще це лікує?",opts:["Iterative refinement loop: оцінити синтез на прогалини, переделегувати запити й повторити синтез","Прийняти синтез як є, лише позначивши наявні прогалини покриття дрібним шрифтом у звіті","Повністю перезапустити всю багатоагентну систему з нуля на ту саму дослідницьку тему","Назавжди подвоїти кількість subagent'ів для всіх майбутніх запитів незалежно від теми"],a:0,ex:"Iterative refinement loop: coordinator оцінює синтез на прогалини покриття, переделеговує search та analysis з націленими запитами й повторно викликає synthesis, доки покриття не стане достатнім. Прийняти результат як є лишає прогалини; повний рестарт і постійне подвоєння агентів неефективні й не цілеспрямовані."},
  {id:"S3Q12",s:3,d:5,q:"Один subagent при збої повертає порожній результат, позначений як «успішний», щоб не «ламати» пайплайн. Чому це anti-pattern і що робити натомість?",opts:["Це мовчазне придушення помилки; треба чітко розрізняти access failure і валідний empty result","Усе гаразд — порожній успіх спрощує обробку результатів у coordinator'а й уникає гілок помилок","Навпаки, треба завершувати весь research-воркфлоу при будь-якому збої одного subagent'а","Достатньо детально логувати збій на бекенді, лишивши агенту поверхневий статус «успіх» без деталей"],a:0,ex:"Мовчазне придушення помилок, коли порожній результат позначають як success, ховає реальний збій і не дає coordinator'у приймати правильні рішення. Завершення всього воркфлоу на один збій subagent'а — теж anti-pattern, бо надмірно реагує. Коректно — розрізняти access failure (збій доступу, що потребує рішення про ретрай чи альтернативу) і валідний empty result (успішний запит без збігів), щоб coordinator приймав правильні рішення. Логування збою лише на бекенді не доходить до контексту агента, тож не допомагає йому адаптуватись."},
  {id:"S3Q13",s:3,d:5,q:"Synthesis-агент має обмежений бюджет контексту, а upstream-агенти повертають багатослівні reasoning-ланцюги й сирий контент. Як це оптимізувати?",opts:["Модифікувати upstream-агентів, щоб вони повертали структуровані дані замість verbose-контенту","Збільшити max_tokens synthesis-агента до максимуму, щоб умістити весь сирий контент і ланцюги міркувань","Прибрати synthesis-крок і зливати тексти upstream-агентів простою конкатенацією геть без жодної обробки","Перенести весь reasoning від upstream-агентів у system prompt synthesis-агента заради повного контексту"],a:0,ex:"Коли downstream-агент має обмежений бюджет контексту, upstream-агенти мають повертати структуровані дані (ключові факти, цитати, relevance scores) замість багатослівного сирого контенту й reasoning-ланцюгів. Збільшення max_tokens не масштабується й не усуває джерело роздування. Конкатенація замість синтезу втрачає сам сенс кроку синтезу. Перенос reasoning у system prompt лише ще більше роздуває контекст, який і так у дефіциті."},
  {id:"S3Q14",s:3,d:1,q:"Команда хоче кращої спостережуваності й узгодженої обробки помилок у багатоагентній системі. Як організувати комунікацію subagent'ів?",opts:["Маршрутизувати всю комунікацію subagent'ів через coordinator у моделі hub-and-spoke","Дозволити subagent'ам напряму викликати одне одного заради швидкості й менше round trips","Зробити спільну глобальну пам'ять, куди всі агенти одночасно пишуть і читають результати","Прибрати coordinator і вибудувати subagent'ів у лінійний ланцюг із передачею далі"],a:0,ex:"Hub-and-spoke означає, що coordinator керує всією міжагентною комунікацією, обробкою помилок і маршрутизацією інформації — саме це дає спостережуваність, єдину обробку помилок і контрольований потік. Прямі виклики між subagent'ами руйнують централізований контроль і трасування. Спільна глобальна пам'ять з одночасним записом створює гонки й непрозорість. Лінійний ланцюг без координатора позбавляє системи централізованого нагляду й гнучкої маршрутизації."},
  {id:"S3Q15",s:3,d:2,q:"Synthesis-агент час від часу намагається сам робити веб-пошуки й використовує інструменти поза своєю спеціалізацією, псуючи результат. Який принцип розподілу інструментів допоможе?",opts:["Обмежити набір інструментів кожного subagent'а лише тими, що релевантні саме його ролі","Дати всім subagent'ам однаковий повний набір усіх інструментів заради гнучкості всієї системи","Прибрати в synthesis-агента геть усі інструменти, лишивши йому тільки роботу з текстом","Форсувати tool_choice synthesis-агента на web-search, щоб уніфікувати його поведінку з рештою"],a:0,ex:"Агенти, що мають інструменти поза своєю спеціалізацією, схильні їх неправильно вживати (cross-specialization misuse). Рішення — scoped tool access: давати кожному subagent'у лише ті інструменти, що релевантні його ролі, запобігаючи misuse. Однаковий повний набір усім лише посилює проблему. Повне позбавлення synthesis-агента інструментів зламає його легітимні задачі. Форсування tool_choice на web-search узагалі помилкове, бо нав'язує synthesis-агенту чужу для нього дію."},
  {id:"S3Q16",s:3,d:1,q:"Як краще написати промпт coordinator'а для subagent'ів, щоб ті лишались адаптивними?",opts:["Задавати дослідницькі цілі та критерії якості, лишаючи subagent'ам простір самим обирати шлях","Прописувати точний step-by-step сценарій для кожного subagent'а з фіксованою послідовністю дій","Давати лише назву теми без жодних цілей і критеріїв, повністю покладаючись на ініціативу агента","Жорстко фіксувати кількість джерел і слів для кожного агента, щоб уніфікувати їхні результати"],a:0,ex:"Промпти coordinator'а для subagent'ів мають специфікувати дослідницькі цілі й критерії якості, а не покрокові процедурні інструкції — це лишає subagent'ам простір адаптуватись до того, що вони знаходять. Жорсткий step-by-step сценарій і жорсткі ліміти на джерела/слова сковують адаптивність. Гола назва теми без жодних критеріїв, навпаки, дає неконтрольований і непередбачуваний результат."},
  {id:"S4Q1",s:4,d:2,q:"Інженер просить знайти всі місця виклику конкретної функції по кодбазі. Який built-in інструмент обрати?",opts:["Grep — пошук за вмістом файлів: імена функцій і рядки помилок","Glob — пошук файлів за патерном імені чи розширення по дереву","Read — послідовно читати кожен файл цілком, шукаючи виклики очима","Bash із інтерактивним редактором для ручного перегляду коду"],a:0,ex:"Grep призначений для пошуку за вмістом коду (наприклад, усі виклики функції за іменем, рядки помилок чи import'и). Пошук файлів за патерном імені знаходить лише файли, а не входження тексту в них. Читання кожного файлу цілком читає вміст конкретного файлу, а не шукає по всіх одразу. Інтерактивний редактор через Bash тут недоречний."},
  {id:"S4Q2",s:4,d:2,q:"Потрібно знайти всі тестові файли за патерном **/*.test.tsx по проєкту. Який інструмент пасує?",opts:["Glob — пошук шляхів файлів за патерном імені чи розширення","Grep — пошук текстових входжень усередині вмісту файлів","Edit — точкова заміна фрагмента за унікальним текстом-якорем","Write — створення нового файлу або повний перезапис наявного"],a:0,ex:"Glob знаходить файли за патернами імен (наприклад, **/*.test.tsx). Пошук за вмістом призначений для входжень тексту в коді, а не для перебору шляхів. Точкова заміна за якорем і створення файлу служать для модифікації чи генерації, а не для пошуку."},
  {id:"S4Q3",s:4,d:2,q:"Edit падає, бо текст-якір, який ви хочете замінити, зустрічається в файлі неунікально. Який надійний fallback?",opts:["Прочитати файл цілком через Read, тоді переписати через Write","Повторювати Edit кілька разів поспіль, доки заміна не спрацює","Видалити файл і створити його заново наосліп через Write","Перейти на Grep, щоб ним змінити потрібний вміст у файлі"],a:0,ex:"Коли Edit не може знайти унікальний якір, надійний fallback — завантажити повний вміст через Read й перезаписати через Write. Повтори Edit не усувають неунікальність якоря, тож вони не спрацюють. Видалення файлу й створення наосліп ризикує втратою вмісту. Grep лише шукає за вмістом і нічого не редагує."},
  {id:"S4Q4",s:4,d:2,q:"Агент має зрозуміти незнайому кодбазу. Який підхід до дослідження найефективніший за контекстом?",opts:["Інкрементально: Grep для точок входу, далі Read по import'ах і потоках даних","Прочитати всі файли проєкту наперед через Read задля повної цілісної картини","Покластися лише на самі назви файлів через Glob, узагалі не читаючи їх вміст","Виконати Bash-скрипт, що друкує весь код усього проєкту прямо в консоль"],a:0,ex:"Розуміння будують інкрементально: Grep для пошуку точок входу, потім Read для трасування import'ів і потоків даних. Читання всіх файлів наперед з'їдає контекст без потреби. Самі лише назви файлів не дають уявлення про логіку. Дамп усього коду в консоль так само переповнює контекст і не структурує дослідження."},
  {id:"S4Q5",s:4,d:2,q:"Команда хоче спільний MCP-сервер з автентифікацією токеном, доступний усім у проєкті, без коміту секретів у репозиторій. Як налаштувати?",opts:["Project-scoped .mcp.json з expansion змінних оточення для токена, напр. ${GITHUB_TOKEN}","Захардкодити токен прямо в .mcp.json і потім закомітити його у спільний репозиторій","Покласти конфіг у ~/.claude.json кожного окремого розробника проєкту поіменно","Передавати токен у тексті кожного промпта вручну під час кожної робочої сесії"],a:0,ex:"Спільні командні MCP-сервери конфігурують у project-scoped .mcp.json, а токени підставляють через expansion змінних оточення — секрети не комітяться в репозиторій. Хардкод токена витікає в історію репозиторію. Конфіг у домашній директорії кожного — user-scope, що не шериться як командний. Ручна передача токена в промпті небезпечна й непрактична."},
  {id:"S4Q6",s:4,d:2,q:"Розробник хоче підключити особистий експериментальний MCP-сервер лише для себе, не зачіпаючи команду. Куди його прописати?",opts:["У user-scoped ~/.claude.json у домашній директорії розробника","У project-scoped .mcp.json репозиторію, доступному всій команді","У кореневий CLAUDE.md проєкту як секцію з конфігурацією сервера","У .claude/commands/ репозиторію, оформивши як slash-команду"],a:0,ex:"Особисті чи експериментальні MCP-сервери прописують у user-scoped ~/.claude.json — вони діють лише для цього розробника. Project-scoped .mcp.json зробив би сервер командним. Файл контексту проєкту й директорія команд не призначені для конфігурації MCP-серверів."},
  {id:"S4Q7",s:4,d:2,q:"Ви додали потужний MCP-інструмент пошуку, але агент усе одно віддає перевагу built-in Grep і майже не кличе ваш інструмент. Який найкращий перший крок?",opts:["Покращити опис MCP-інструмента: можливості, формати виводу, межі","Видалити built-in інструмент Grep у агента взагалі, лишивши лише MCP","Форсувати tool_choice завжди на цей MCP-інструмент примусово","Перейменувати built-in Grep, щоб заплутати агента й відштовхнути"],a:0,ex:"Якщо агент віддає перевагу built-in над кращим MCP-інструментом, перший крок — підсилити опис MCP-інструмента (можливості, формати виводів, коли його застосовувати), щоб він став очевидним вибором. Описи — основний механізм вибору інструмента моделлю. Видалення Grep і примусове форсування tool_choice — грубі обхідні шляхи, що ламають гнучкість; навмисне перейменування built-in — anti-pattern."},
  {id:"S4Q8",s:4,d:2,q:"Агент щоразу робить багато exploratory-викликів, щоб дізнатися, які дані взагалі доступні (перелік issue, ієрархія документації, схеми БД). Що зменшить ці зайві виклики?",opts:["Виставити каталоги контенту як MCP resources для видимості даних","Збільшити max_tokens, щоб умістити більше результатів пошуку за раз","Додати ще окремих інструментів пошуку під кожен тип доступних даних","Кешувати результати exploratory-викликів на бекенді між сесіями"],a:0,ex:"MCP resources — це механізм виставити каталоги контенту (переліки issue, ієрархії документації, схеми БД), щоб агент бачив доступні дані наперед без exploratory tool calls. Збільшення max_tokens лише розширює вивід, не даючи оглядовості. Додавання інструментів множить виклики замість їх скорочення. Кеш на бекенді не доходить до агента як видимість структури даних."},
  {id:"S4Q9",s:4,d:2,q:"Вам потрібна стандартна інтеграція з Jira. Що краще — писати власний MCP-сервер чи взяти готовий?",opts:["Узяти готовий community MCP-сервер, а кастомні лишити під свої воркфлоу","Завжди писати власний MCP-сервер заради повного контролю над кодом","Не використовувати MCP взагалі, а парсити Jira через Bash і curl-запити","Виставити інтеграцію з Jira як секцію у CLAUDE.md-файлі проєкту"],a:0,ex:"Для стандартних інтеграцій (наприклад, Jira) обирають готові community MCP-сервери, а власні кастомні лишають для специфічних командних воркфлоу. Завжди писати свій сервер — зайва робота й підтримка. Парсинг через Bash і curl крихкий і не структурований. Файл контексту проєкту не є транспортом для інтеграції з зовнішнім сервісом."},
  {id:"S4Q10",s:4,d:1,q:"Задача: «додати вичерпні тести до великої legacy-кодбази». Це відкрита задача без наперед відомого плану. Яка стратегія декомпозиції підходить?",opts:["Dynamic adaptive: мапа структури, high-impact зони, пріоритезований план","Fixed sequential pipeline із наперед заданими однаковими кроками для всіх","Згенерувати тести для всіх файлів одним проходом без попереднього плану","Просити користувача наперед перелічити всі потрібні тести вручну"],a:0,ex:"Відкриті дослідницькі задачі вимагають динамічної адаптивної декомпозиції: спершу зкартувати структуру кодбази, виявити high-impact зони, тоді скласти пріоритезований план, що адаптується в міру виявлення залежностей. Fixed pipeline пасує передбачуваним задачам із відомими кроками. One-pass без плану й повний список тестів наперед нереалістичні для великої legacy-кодбази."},
  {id:"S4Q11",s:4,d:1,q:"Вам треба передбачуваний багатоаспектний code review: проаналізувати кожен файл окремо, а потім зробити окремий крос-файловий інтеграційний прохід. Який патерн декомпозиції це?",opts:["Prompt chaining — фіксований послідовний пайплайн із чітких кроків","Dynamic decomposition, що адаптується на основі проміжних знахідок","Single-pass аналіз усіх файлів разом одним великим проходом","Fork-based exploration кількох паралельних гілок рішення"],a:0,ex:"Для передбачуваних багатоаспектних рев'ю пасує prompt chaining — фіксована послідовність чітких кроків (наприклад, аналіз кожного файлу окремо, тоді окремий крос-файловий інтеграційний прохід). Динамічна декомпозиція призначена для відкритих задач без наперед відомого плану. Single-pass аналіз усього разом дає attention dilution. Fork-based exploration — про дивергентні паралельні гілки, а не послідовний пайплайн."},
  {id:"S4Q12",s:4,d:1,q:"Ви повертаєтесь до конкретної названої сесії розслідування, щоб продовжити її через день. Який механізм використати?",opts:["--resume <session-name>, щоб продовжити саме цю названу розмову","fork_session, щоб створити нову незалежну гілку від спільної бази","/compact на поточній сесії для стиснення накопиченого контексту","Нову сесію з нуля, надавши тему розслідування вручну в промпті"],a:0,ex:"Названу сесію продовжують через --resume <session-name> — він відновлює саме цю попередню розмову з її повним контекстом за день. Створення нової гілки через fork_session призначене для дивергентних відгалужень від спільної бази, а не для повернення до тієї самої лінії. Стиснення поточного контексту лише ужимає вже відкриту сесію й не відновлює минулу. Старт нової сесії з ручним описом теми втрачає всі попередні напрацювання розслідування."},
  {id:"S4Q13",s:4,d:1,q:"Ви хочете порівняти два підходи до рефакторингу, стартуючи з однакового базового аналізу кодбази, але в незалежних гілках. Що використати?",opts:["fork_session — створити незалежні гілки від спільного analysis baseline для дивергентних гілок","--resume однієї й тієї ж сесії, по черзі проганяючи в ній обидва різні підходи до рефакторингу","Дві повністю незалежні сесії з нуля, наново повторивши однаковий аналіз кодбази в кожній","/memory, щоб роздвоїти вже завантажений контекст на дві окремі паралельні незалежні лінії"],a:0,ex:"fork_session створює незалежні гілки від спільного baseline — обидві стартують з однакового аналізу кодбази, далі розходяться для дивергентних підходів. Це ідеально для порівняння двох стратегій рефакторингу без перехресного впливу. Продовження однієї сесії через resume змішало б обидва підходи в одній лінії контексту. Дві сесії з нуля втрачають спільну базу й змушують дублювати аналіз. Команда перегляду memory-файлів узагалі не створює відгалужень сесії."},
  {id:"S4Q14",s:4,d:1,q:"Ви відновлюєте сесію після того, як кілька раніше проаналізованих файлів були змінені поза Claude. Як діяти найнадійніше?",opts:["Повідомити сесію про конкретні зміни файлів для націленого ре-аналізу, а за загальної застарілості — стартувати свіжу","Просто продовжити через --resume і покластися на наявні старі tool-результати як на цілком актуальні без жодної перевірки","Завжди починати з нуля, ігноруючи весь попередній валідний контекст усього розслідування, його файли і знахідки","Підвищити max_tokens, щоб у контекст-вікно вмістились одразу і старий, і новий стан геть усіх змінених файлів"],a:0,ex:"Важливо повідомити агенту про конкретні зміни файлів для цільового ре-аналізу; коли ж попередні tool-результати застаріли загалом, надійніше почати свіжу сесію зі структурованим summary, ніж відновлювати її поверх stale-даних. Сліпе відновлення з опорою на старі результати ризикує діяти на застарілому стані. Завжди-з-нуля марнує валідний контекст там, де достатньо точкового оновлення. Збільшення ліміту токенів стосується обсягу вікна, а не свіжості даних."},
  {id:"S4Q15",s:4,d:2,q:"У вас є один загальний інструмент analyze_document, який модель застосовує по-різному й непослідовно. Який рефакторинг покращить надійність?",opts:["Розбити його на purpose-specific інструменти з чіткими input/output контрактами для кожного","Лишити один інструмент, але вдвічі збільшити його опис із численними прикладами застосувань","Об'єднати його ще з кількома наявними інструментами в один універсальний all-in-one","Форсувати tool_choice завжди на analyze_document, щоб модель не вагалась при виклику"],a:0,ex:"Загальні інструменти, які модель застосовує непослідовно, розбивають на purpose-specific із визначеними контрактами входу/виходу — кожен закриває одне чітке призначення (витяг даних extract_data_points, сумаризація summarize_content, верифікація твердження проти джерела verify_claim_against_source), що усуває неоднозначність застосування. Просто вдвічі довший опис не міняє суті generic-інструмента. Об'єднання з іншими в універсальний інструмент лише посилює плутанину. Форсування одного й того ж інструмента не вирішує того, як саме його застосовувати."},
  {id:"S4Q16",s:4,d:2,q:"Ви хочете гарантувати, що модель викличе якийсь інструмент, а не поверне просто текстову відповідь. Яке налаштування tool_choice використати?",opts:["tool_choice: \"any\" — модель зобов'язана викликати якийсь інструмент, хоч і сама обирає, який саме","tool_choice: \"auto\" — модель сама вирішує і може повернути текст замість виклику інструмента","tool_choice: {\"type\":\"tool\",\"name\":\"...\"} — форсувати конкретний інструмент, навіть якщо потрібен будь-який","Прибрати всі інструменти з запиту, щоб модель фізично могла повернути лише текст"],a:0,ex:"tool_choice: \"any\" гарантує, що модель викличе якийсь інструмент, а не поверне conversational-текст, лишаючи їй вибір конкретного інструмента. Режим auto дозволяє моделі повернути текст замість виклику, тож мети не досягає. Форсування конкретного інструмента за іменем недоречне, коли потрібен будь-який, а не один заданий. Прибирання всіх інструментів дає протилежний результат — лишається тільки текст."},
  {id:"S5Q1",s:5,d:3,q:"Ваш pipeline-скрипт запускає claude \"Analyze this PR for security issues\", але job висить нескінченно — Claude Code чекає на інтерактивний ввід. Який правильний підхід для автоматизованого пайплайну?",opts:["Додати прапорець -p у виклик claude для неінтерактивного режиму обробки промпту в CI","Виставити змінну оточення CLAUDE_HEADLESS=true перед запуском команди claude в пайплайні CI","Перенаправити stdin з /dev/null, щоб процес узагалі не чекав на жодний інтерактивний ввід","Додати прапорець --batch для пакетної неінтерактивної обробки промпту в пайплайні CI системи"],a:0,ex:"Прапорець -p (--print) — задокументований спосіб запуску Claude Code в неінтерактивному режимі: обробляє промпт, друкує результат у stdout і одразу виходить, не чекаючи інтерактивного вводу. Змінна CLAUDE_HEADLESS і прапорець --batch — неіснуючі й не вмикають headless-режим. Редирект stdin з /dev/null — обхідний трюк, що не відповідає офіційному синтаксису Claude Code і не гарантує коректного завершення."},
  {id:"S5Q2",s:5,d:4,q:"Команда хоче зменшити витрати на API. Зараз real-time виклики живлять два воркфлоу: (1) блокуючий pre-merge check, який має завершитись до merge, і (2) звіт по tech debt, що генерується вночі для ранкового перегляду. Менеджер пропонує перевести обидва на Message Batches API заради 50% економії. Як оцінити?",opts:["Перевести на batch лише нічні звіти по tech debt, а блокуючі pre-merge checks свідомо лишити на real-time","Перевести обидва воркфлоу на batch і відстежувати готовність кожного результату через status polling","Лишити обидва воркфлоу на real-time, щоб уникнути проблем із кореляцією й порядком результатів","Перевести обидва на batch, додавши timeout-fallback на real-time для запізнілих результатів"],a:0,ex:"Batches API дає 50% економії, але час обробки — до 24 годин без гарантії latency. Це неприйнятно для блокуючого pre-merge check, який має завершитись до merge, але ідеально для нічних звітів, що читають уранці. Переведення обох на batch покладається на «зазвичай швидше» — неприйнятно для блокуючого кроку. Побоювання про порядок результатів хибне: відповіді корелюються через custom_id. Timeout-fallback на real-time — зайва складність, що не усуває ризику для блокуючого кроку."},
  {id:"S5Q3",s:5,d:4,q:"PR змінює 14 файлів у модулі обліку. Single-pass рев'ю всіх файлів разом дає непослідовний результат: десь детальний фідбек, десь поверхневий, очевидні баги пропущені, а інколи фідбек суперечливий — патерн позначено проблемним в одному файлі й схвалено ідентичний код в іншому. Як перебудувати рев'ю?",opts:["Розбити на сфокусовані проходи: окремий аналіз кожного файлу й integration-прохід по крос-файлах","Вимагати від розробників розбивати великі PR на групи по 3–4 файли ще до запуску авто-рев'ю в CI","Перейти на модель із більшим контекстним вікном, щоб умістити всі 14 файлів разом за один прохід","Зробити три незалежні проходи й флагати лише ті проблеми, що з'явились мінімум у двох із них тут"],a:0,ex:"Корінь проблеми — attention dilution при обробці багатьох файлів разом: глибина уваги розмивається, тому фідбек нерівний і суперечливий. Розбиття на per-file проходи дає рівну глибину для кожного файлу, а окремий integration-прохід ловить крос-файлові потоки даних. Перекладання поділу PR на розробників перекладає тягар на людей і не лікує причину. Більше контекстне вікно — хибне уявлення: більший контекст не означає кращу увагу до кожного файлу. Три проходи з порогом «мінімум у двох» придушують реальні баги, які ловляться лише в одному з проходів."},
  {id:"S5Q4",s:5,d:3,q:"Ви хочете, щоб у CI Claude Code видавав машиночитні findings для автоматичного постингу як inline-коментарі до PR. Які CLI-прапорці це забезпечують?",opts:["Прапорці --output-format json разом із --json-schema для структурованого машиночитного виводу","Прапорець --verbose для повного тексту findings із подальшим парсингом результату регулярками","Прапорець --interactive, щоб уточнити бажаний формат виводу в діалозі перед постингом","Прапорець --markdown для красивого форматування findings як готових PR-коментарів"],a:0,ex:"Поєднання --output-format json із --json-schema продукує машиночитні структуровані findings із гарантованою формою, придатні для автоматичного постингу як inline PR-коментарі. Verbose-текст із парсингом регулярками крихкий до формулювань і ламається на змінах виводу. Інтерактивний режим повісить CI, бо чекатиме на ввід людини. Markdown-форматування дає гарний текст, але не надійну структуру для програмного парсингу."},
  {id:"S5Q5",s:5,d:4,q:"Ваш промпт каже «перевір, що коментарі точні», і це дає багато false positives. Як переформулювати критерій, щоб підвищити точність?",opts:["Дати явний категоріальний критерій: флагати коментар, лише коли заявлена в ньому поведінка суперечить коду","Додати загальну настанову бути консервативним і повідомляти лише про high-confidence знахідки в коментарях","Просити модель саму оцінювати власну впевненість і фільтрувати знахідки нижче певного порогу","Збільшити max_tokens, щоб модель мала більше простору ретельніше перевіряти кожен коментар"],a:0,ex:"Явний категоріальний критерій — флагати лише коли заявлена в коментарі поведінка прямо суперечить фактичній поведінці коду — дає моделі чітку межу рішення й різко знижує false positives. Розмиті заклики бути консервативним чи повідомляти лише high-confidence не задають, що саме звітувати, тож precision не зростає. Самооцінка впевненості погано калібрована й не замінює конкретного критерію. Збільшення max_tokens не стосується точності класифікації — воно лише дає більше місця під вивід."},
  {id:"S5Q6",s:5,d:4,q:"Менеджер пропонує знизити false positives, додавши в промпт «звітуй лише про high-confidence проблеми» та «будь обережним». Чому це слабке рішення?",opts:["Розмиті заклики бути консервативним не дають precision; потрібні категоріальні критерії","Це сильне й цілком достатнє рішення, саме так і варто формулювати інструкції для рев'ю","Проблема лише в слові обережним, тож достатньо замінити його на суворішим і все запрацює","Достатньо знизити temperature до нуля, і тоді кількість false positives помітно зменшиться"],a:0,ex:"Розмиті заклики до обережності чи впевненості не підвищують precision. Дієве — специфічні категоріальні критерії: що саме звітувати (баги, security-проблеми) і що пропускати (дрібний стиль). Заміна окремих слів чи нульова temperature суті завдання не змінюють."},
  {id:"S5Q7",s:5,d:4,q:"Та сама Claude-сесія, що згенерувала код, гірше знаходить у ньому власні тонкі помилки, навіть з інструкцією «перевір себе» чи extended thinking. Який підхід ефективніший?",opts:["Другий незалежний інстанс Claude без reasoning-контексту генерації для свіжого рев'ю коду","Додати в той самий промпт інструкцію уважно перевірити власний згенерований код щонайменше двічі","Увімкнути extended thinking у тій самій сесії, щоб модель глибше проаналізувала власні рішення","Підняти temperature на етапі самоперевірки, щоб модель розглянула альтернативні трактування коду"],a:0,ex:"Модель зберігає reasoning-контекст генерації й менш схильна сумніватись у власних рішеннях у межах тієї самої сесії. Незалежний review-інстанс підходить до коду «свіжим поглядом» без цього контексту й ефективніше ловить тонкі помилки. Інструкція перевірити себе двічі лишається в тому ж контексті й не усуває упередженості. Extended thinking у тій самій сесії поглиблює міркування на тому ж reasoning-сліді. Підняття temperature додає варіативності, але не дає незалежної точки зору."},
  {id:"S5Q8",s:5,d:3,q:"Після нових комітів ви повторно ганяєте рев'ю, і Claude постить дублікати коментарів на ті самі проблеми, що вже були. Як це усунути?",opts:["Передавати попередні findings у контекст і просити звітувати лише про нові чи досі невиправлені проблеми","Видаляти всі попередні коментарі рев'ю перед кожним повторним запуском, щоб не лишалось дублікатів","Запускати рев'ю лише один раз на весь PR і більше взагалі не повторювати після наступних комітів","Знизити max_tokens, щоб модель суто фізично згенерувала менше коментарів за повторний прохід"],a:0,ex:"При повторних рев'ю після нових комітів попередні findings передають у контекст і просять звітувати лише нові або досі невиправлені проблеми — це детерміновано уникає дублів, зберігаючи історію. Видалення попередніх коментарів втрачає вже наявну дискусію й контекст для розробників. Одноразове рев'ю ламає сам процес ітеративного контролю якості. Зниження max_tokens ріже вивід наосліп і може відрізати справжні нові проблеми разом із дублями."},
  {id:"S5Q9",s:5,d:4,q:"Детальні інструкції все одно дають непослідовний формат фідбеку рев'ю. Який прийом найкраще дає консистентний, actionable формат?",opts:["Few-shot приклади бажаного формату виводу рев'ю: location, issue, severity, suggested fix","Ще детальніша прозова специфікація бажаного формату з повним переліком обов'язкових полів виводу","Просити модель самостійно вигадувати зручну для неї структуру виводу під кожен окремий прохід","Збільшити кількість проходів рев'ю, щоб формат поступово стабілізувався між повторними запусками"],a:0,ex:"Few-shot приклади — найдієвіший спосіб домогтися консистентного, actionable формату (location, issue, severity, suggested fix), коли самих текстових інструкцій недостатньо: модель узагальнює показаний патерн. Детальніша проза вже не спрацювала за умовою й не дає стабільності. Свобода вибору формату для моделі прямо суперечить меті консистентності. Більше проходів рев'ю не стосується формату — вони лише повторюють ту саму нестабільність."},
  {id:"S5Q10",s:5,d:3,q:"Авто-генерація тестів у CI пропонує тести, що дублюють уже наявні сценарії. Як це зменшити?",opts:["Передавати наявні тестові файли в контекст, щоб генерація уникала дублювання вже покритих сценаріїв","Збільшити кількість згенерованих тестів, розраховуючи «перекрити» дублі додатковим обсягом покриття","Вимкнути авто-генерацію тестів узагалі, повернувши написання всіх тестів виключно на розробників","Генерувати тести випадково й видаляти схожі вже постфактум окремим кроком дедуплікації виводу"],a:0,ex:"Щоб уникнути дублів, наявні тестові файли подають у контекст — генерація бачить, що вже покрито, і доповнює непокриті сценарії. Збільшення кількості тестів лише множить дублікати. Повне вимкнення авто-генерації втрачає її користь у CI. Випадкова генерація з постфактумною дедуплікацією неефективна: марнує токени на тести, які потім відкидаються."},
  {id:"S5Q11",s:5,d:3,q:"Якість і цінність авто-генерованих тестів у CI низька — багато low-value тестів. Який механізм найкраще передає Claude Code потрібний контекст у CI?",opts:["Документувати у CLAUDE.md стандарти тестування, критерії цінних тестів і доступні fixtures проєкту","Класти всі інструкції в один довгий рядок CLI-команди при кожному окремому запуску в пайплайні CI","Покладатися на дефолтну поведінку моделі без передачі їй жодного контексту про стандарти проєкту","Зберігати стандарти тестування лише у вікі команди, що лежить геть поза репозиторієм із кодом проєкту"],a:0,ex:"CLAUDE.md — призначений механізм передати CI-інстансу Claude Code контекст проєкту: стандарти тестування, критерії цінних тестів і доступні fixtures. Він версіонується разом із кодом і автоматично підхоплюється, що підвищує якість і ріже low-value вивід. Довгий CLI-рядок при кожному запуску некерований і дорогий за токенами. Дефолти без контексту лишають проблему. Зовнішня вікі до моделі не доходить без явного читання, тож CI-інстанс її не бачить."},
  {id:"S5Q12",s:5,d:4,q:"Ви ганяєте документи через Batches API (обробка до 24 год) і маєте дотриматись SLA 30 годин. Як спланувати подачу батчів?",opts:["Подавати батчі у вікнах близько 4 годин, щоб гарантувати дотримання SLA","Подати все одним великим батчем раз на добу й сподіватись, що обробка встигне вчасно","Перейти на синхронний API, бо batch-обробка не підходить для жодних SLA-обмежень","Подавати кожен документ окремим мінібатчем щохвилини протягом доби"],a:0,ex:"Частоту подачі рахують від SLA-обмежень: при обробці до 24 годин і цілі 30 годин вікна подачі близько 4 годин залишають достатній запас і гарантують дотримання SLA. Один великий батч раз на добу ризикує не вкластися у вікно, бо сама обробка може зайняти всі 24 години. Повна відмова від batch на користь синхронного API втрачає економію коштів, яку дає пакетна обробка. Подача по одному документу окремими батчами неефективна за накладними витратами й нічого не виграє за часом."},
  {id:"S5Q13",s:5,d:4,q:"Одна категорія перевірок дає стільки false positives, що розробники втрачають довіру навіть до точних категорій. Який прагматичний крок?",opts:["Тимчасово вимкнути категорію з високим FP, паралельно покращуючи її промпт","Лишити все як є, оскільки довіра розробників відновиться сама собою з часом","Знизити загальну кількість усіх знахідок наполовину незалежно від категорії","Видалити всі категорії перевірок, окрім перевірки стилю коду"],a:0,ex:"Високий рівень false positives в одній категорії підриває довіру навіть до точних категорій. Прагматично — тимчасово вимкнути проблемну категорію, відновити довіру й паралельно доопрацьовувати її промпт для зниження хибних спрацювань. Бездіяльність не усуває причину й довіра не повернеться сама. Сліпе скорочення всіх знахідок наполовину ріже й справжні баги. Лишання тільки перевірки стилю викидає цінні категорії й не вирішує проблему адресно."},
  {id:"S5Q14",s:5,d:4,q:"Воркфлоу потребує, щоб у межах одного запиту модель викликала інструмент, отримала результат і продовжила міркувати (multi-turn tool calling). Чи годиться для цього Batches API?",opts:["Ні — Batches API не підтримує multi-turn tool calling у межах одного запиту","Так — batch повністю підтримує multi-turn tool calling, треба лише налаштувати polling","Так, якщо додати унікальний custom_id до кожного окремого ходу всередині запиту","Так, але це працює лише з увімкненим прапорцем --interactive у запиті"],a:0,ex:"Batch API не підтримує multi-turn tool calling у межах одного запиту: не можна виконати інструмент посеред запиту, отримати результат і повернути його моделі для продовження міркувань. Для такого воркфлоу потрібен синхронний API. Жодне налаштування polling цього не змінює, бо обмеження архітектурне. Поле custom_id лише корелює пари запит/відповідь у пакеті, а не вмикає інтерактивний обмін. Прапорця --interactive для Batches API не існує."},
  {id:"S5Q15",s:5,d:3,q:"Чому в CI-рев'ю варто використовувати окремий інстанс Claude, а не ту саму сесію, що згенерувала код?",opts:["Та сама сесія зберігає reasoning-контекст генерації й гірше критикує власні зміни","Бо одна сесія не може фізично виконати вбудований інструмент Read більше одного разу","Бо окремі інстанси Claude завжди примусово використовують різні базові моделі","Бо це єдиний технічний спосіб увімкнути режим виводу --output-format json"],a:0,ex:"Session context isolation: сесія, що згенерувала код, менш об'єктивна в рев'ю власних змін через збережений reasoning-контекст генерації — вона схильна виправдовувати власні рішення. Незалежний інстанс підходить до коду свіжим поглядом і критикує об'єктивніше. Твердження про неможливість повторного виклику Read хибне. Окремі інстанси не зобов'язані використовувати різні моделі. Формат виводу json не залежить від того, та сама сесія чи інша."},
  {id:"S5Q16",s:5,d:4,q:"Колега боїться, що few-shot приклади змусять модель ловити лише ті патерни, що в прикладах, і пропускати нові. Що насправді?",opts:["Few-shot приклади дозволяють моделі узагальнювати судження й на нові, не бачені раніше патерни","Так і є — few-shot завжди жорстко обмежує модель лише наведеними в прикладах кейсами","Few-shot впливає тільки на форматування виводу, але не на якість самих суджень моделі","Few-shot варто давати строго по одному прикладу, інакше це лише шкодить точності"],a:0,ex:"Few-shot приклади допомагають моделі генералізувати судження на нові, не бачені в прикладах патерни, а також демонструють обробку ambiguous-кейсів і потрібний формат виводу. Тож побоювання, що приклади звузять модель до самих лише наведених кейсів, необґрунтоване. Твердження, що few-shot завжди обмежує модель прикладами, хибне. Few-shot впливає не тільки на форматування, а й на судження. Кілька прикладів зазвичай корисніші за один."},
  {id:"S6Q1",s:6,d:4,q:"Ваша система екстракції інколи повертає синтаксично невалідний JSON, що ламає downstream. Який підхід найнадійніше гарантує schema-compliant вивід без JSON-синтаксичних помилок?",opts:["Tool use (tool_use) з JSON-схемою як вхідними параметрами інструмента виводу","Просити модель у system prompt «повертати валідний JSON» і парсити сирий текст","Лагодити невалідний JSON постфактум регулярками й евристичними патчами","Знизити temperature до нуля, очікуючи, що JSON завжди виходитиме валідним"],a:0,ex:"tool_use із JSON-схемою — найнадійніший спосіб гарантованого schema-compliant виводу: модель повертає структуровані дані саме як вхідні параметри інструмента, і це усуває синтаксичні помилки JSON. Прохання в промпті лишається ймовірнісним; полагодження регулярками крихке й не покриває всі випадки невалідної розмітки; нульова temperature робить вивід детермінованим, але не гарантує відповідності схемі."},
  {id:"S6Q2",s:6,d:4,q:"Деякі вихідні документи не містять певних полів, а модель вигадує значення, щоб задовольнити required-поля схеми. Як це усунути?",opts:["Зробити такі поля optional/nullable, щоб модель повертала null замість фабрикації","Лишити поля required, але додати в промпт чітку інструкцію «не вигадувати відсутні значення»","Видалити ці поля зі схеми взагалі, щоб модель навіть не намагалась їх якось заповнити","Підвищити max_tokens, щоб модель довше шукала відсутні значення десь у тексті документа"],a:0,ex:"Поля, яких може не бути в джерелі, проєктують optional/nullable — тоді модель повертає null, коли даних немає, замість того, щоб під required-обмеження фабрикувати значення. Прохання «не вигадувати» лишається ймовірнісним; повне видалення полів зі схеми втрачає дані там, де вони насправді присутні; збільшення max_tokens не створить відсутню в документі інформацію."},
  {id:"S6Q3",s:6,d:4,q:"Валідація екстракції зафейлила (Pydantic/JSON-схема). Як побудувати retry, щоб модель виправилась?",opts:["Follow-up-запит з оригінальним документом, проваленою екстракцією й конкретними помилками валідації","Просто повторити той самий запит ще раз без жодних змін і сподіватися на кращий результат","Підвищити temperature й сподіватися, що модель цього разу видасть зовсім іншу відповідь","Одразу відкинути цей документ як принципово необроблюваний і перейти до наступного далі"],a:0,ex:"Retry-with-error-feedback: у follow-up-запиті додають оригінальний документ, провалену екстракцію й конкретні помилки валідації — це скеровує модель до самокорекції. Сліпий повтор і підняття temperature не дають напрямку; відкидання документа передчасне для виправних помилок."},
  {id:"S6Q4",s:6,d:4,q:"Валідація вимагає поле, якого в наданому документі просто немає (потрібна інформація існує лише в зовнішньому документі, що не передавався). Чи допоможе retry?",opts:["Ні — retry безсилий, коли потрібної інформації немає в джерелі; це не структурна помилка","Так — достатньо повторити запит кілька разів, і модель зрештою таки знайде потрібне значення","Так, якщо додати в промпт наполегливий заклик «дуже постарайся знайти це значення в тексті»","Так, якщо підвищити max_tokens, щоб модель довше й уважніше аналізувала наданий документ"],a:0,ex:"Retry дієвий для format/structural помилок, але безсилий, коли потрібна інформація просто відсутня в наданому джерелі (вона існує лише в зовнішньому документі, що не передавався), і це не format/structural помилка. Повтори, заклики «постарайся» чи більший max_tokens не створять відсутні дані — потрібен інший документ або позначення поля як відсутнього (optional/nullable)."},
  {id:"S6Q5",s:6,d:4,q:"Тип вхідного документа наперед невідомий, і у вас є кілька схем екстракції під різні типи. Як гарантувати, що модель таки викличе якусь extraction-схему, а не поверне текст?",opts:["Виставити tool_choice: \"any\", щоб модель була зобов'язана викликати один із extraction-інструментів","Виставити tool_choice: \"auto\", щоб модель сама вирішила, чи взагалі потрібен їй якийсь окремий інструмент","Форсувати один конкретний інструмент через {\"type\":\"tool\",\"name\":\"...\"} однаково для всіх документів","Прибрати схеми екстракції взагалі й покластися на вивід моделі у форматі вільного тексту без структури"],a:0,ex:"Коли тип документа наперед невідомий, а схем кілька, tool_choice: \"any\" гарантує виклик якогось extraction-інструмента — модель сама обере відповідний під тип документа. Режим \"auto\" дозволяє моделі повернути текст без інструмента; форсування одного конкретного інструмента недоречне, бо тип невідомий і схема може не підійти; вільний текст — пряма протилежність меті структурованої екстракції."},
  {id:"S6Q6",s:6,d:4,q:"Вам треба, щоб у пайплайні спершу гарантовано відпрацював саме extract_metadata, а вже потім — кроки збагачення. Як це забезпечити?",opts:["Форсувати tool_choice: {\"type\":\"tool\",\"name\":\"extract_metadata\"}, а кроки збагачення лишити на наступні ходи","Виставити tool_choice: \"any\" і сподіватись, що метадані оброблять найпершими серед усіх інструментів","Виставити tool_choice: \"auto\" разом з інструкцією в промпті про потрібний порядок викликів інструментів","Запустити всі інструменти пайплайну одночасно й потім відсортувати їх результат за заданим пріоритетом"],a:0,ex:"Щоб гарантувати, що саме extract_metadata викликається першим, форсують tool_choice на цей конкретний інструмент, а наступні кроки збагачення обробляють у подальших (follow-up) ходах. Режим \"any\" зобов'язує викликати якийсь інструмент, але не фіксує саме цей; \"auto\" з інструкцією лишається ймовірнісним; одночасний запуск усіх інструментів не дає гарантованого порядку виконання."},
  {id:"S6Q7",s:6,d:4,q:"Категорії в документах не фіксовані наперед — трапляються нові, плюс бувають неоднозначні випадки. Як спроєктувати поле категорії в схемі?",opts:["Enum зі значенням other і окремим detail-полем, плюс unclear для неоднозначних","Жорсткий enum лише з відомих наперед значень без жодних запасних чи резервних варіантів","Вільний текстовий рядок зовсім без enum, щоб модель писала категорію цілком як завгодно","Required числове поле, що кодує кожну категорію окремим заздалегідь визначеним числом"],a:0,ex:"Для розширюваних категорій додають enum зі значенням other і окремим detail-рядком, а для неоднозначних випадків — значення unclear. Жорсткий enum не вмістить нові категорії; вільний текст втрачає структуру; числовий код непрозорий і крихкий."},
  {id:"S6Q8",s:6,d:4,q:"Навіть з tool_use і строгою схемою екстракції з інвойсів інколи line items не сумуються до total, або значення опиняється в неправильному полі. Що це за тип помилок і як їх ловити?",opts:["Семантичні помилки: ловити через self-correction, флагуючи розбіжність обчисленої та заявленої сум","Це синтаксичні помилки, які механізм tool_use уже повністю й остаточно усуває сам","Достатньо знизити temperature до нуля, і тоді line items завжди коректно сходитимуться","Достатньо просто додати ще одне required-поле total, і проблема невідповідності зникне"],a:0,ex:"Строгі схеми через tool_use усувають синтаксичні помилки, але не семантичні: суми line items не сходяться до total або значення опиняється в чужому полі. Їх ловлять валідацією — витягують calculated_total поряд зі stated_total і флагують розбіжності. Твердження про синтаксичну природу хибне; temperature чи ще одне поле суті не міняють."},
  {id:"S6Q9",s:6,d:5,q:"Ваша система звітує 97% загальної точності екстракції. Чому покладатись лише на цю агрегатну метрику ризиковано перед автоматизацією?",opts:["Агрегатна точність маскує слабкі типи й поля; аналізувати точність по типу й по полю","97% — цілком достатньо для автоматизації, тож додатковий сегментний аналіз тут геть зайвий","Достатньо підняти загальний поріг точності аж до 99%, не розбиваючи саму метрику на сегменти","Достатньо збільшити обсяг тестової вибірки, не розбиваючи її на типи документів і окремі поля"],a:0,ex:"Агрегатна метрика (напр. 97%) може приховувати слабку якість на окремих типах документів або полях — наприклад, висока точність на простих полях компенсує провали на складних. Перед автоматизацією точність валідують у розрізі типу документа й поля. Сама по собі вища планка чи більша, але нерозбита вибірка проблему конкретних сегментів не виявлять."},
  {id:"S6Q10",s:6,d:5,q:"Ви хочете вимірювати реальний рівень помилок саме серед high-confidence екстракцій і ловити нові патерни помилок. Який метод найкращий?",opts:["Stratified random sampling саме серед high-confidence екстракцій для виміру реального error rate","Перевіряти вручну лише ті екстракції, де модель сама позначила низьку впевненість","Перевіряти випадкові 1% усіх екстракцій без жодної стратифікації за впевненістю","Покладатись на самозвітований моделлю confidence без незалежних ручних перевірок"],a:0,ex:"Stratified random sampling саме high-confidence екстракцій вимірює реальний error rate у цьому сегменті й виявляє нові патерни помилок, які інакше лишились би непоміченими «під впевненістю». Перевірка лише low-confidence пропускає приховані помилки серед впевнених; нестратифікований випадковий семпл і сліпа довіра до самозвітованого confidence менш надійні для цієї мети."},
  {id:"S6Q11",s:6,d:5,q:"У вас обмежена reviewer-потужність. Які екстракції варто маршрутизувати на людський перегляд у першу чергу?",opts:["Екстракції з низькою впевненістю моделі або з неоднозначних чи суперечливих джерел з ризиком","Випадкову вибірку всіх екстракцій незалежно від рівня впевненості моделі чи якості вхідного джерела","Лише екстракції з найвищою впевненістю моделі, бо саме вони визначають ключові підсумкові показники","Жодних екстракцій не маршрутизувати: повністю довіряти автоматичній моделі заради економії ресурсу"],a:0,ex:"На людський перегляд маршрутизують екстракції з низькою впевненістю або з неоднозначних чи суперечливих джерел, концентруючи обмежену потужність рев'юерів там, де ризик найбільший. Випадкова вибірка розпорошує ресурс без націлювання на ризик; перегляд лише найвпевненіших кейсів перевіряє те, що й так надійне, лишаючи ризиковані без контролю; повна довіра моделі взагалі прибирає захисний бар'єр там, де він найпотрібніший."},
  {id:"S6Q12",s:6,d:4,q:"Required-поля інколи виходять порожніми/null, бо документи мають дуже різну структуру (inline-цитати vs бібліографії, наративні описи vs структуровані таблиці). Що найкраще покращить обробку цієї варіативності?",opts:["Few-shot приклади, що демонструють коректну екстракцію з документів різної структури й форматів","Зробити всі поля required й заборонити null, щоб модель завжди повертала значення в кожному полі","Прибрати валідацію виводу, щоб порожні чи null-поля більше не блокували downstream-обробку","Збільшити temperature для «креативнішого» пошуку даних у документах із нетиповою структурою"],a:0,ex:"Few-shot приклади різних структур документів (inline-цитати проти бібліографій, наративні описи проти структурованих таблиць) показують моделі, як витягати дані попри варіативність формату, і зменшують кількість порожніх полів. Жорсткі required без null спровокують фабрикацію відсутніх значень; зняття валідації лише ховає проблему, не покращуючи екстракцію; вища temperature додає випадковості, але не вчить розбирати різні структури."},
  {id:"S6Q13",s:6,d:4,q:"Ви подали батч зі 100 документів через Batches API; частина зафейлила, зокрема через перевищення контекстного ліміту. Як обробити збої?",opts:["Перездати лише провалені документи, ідентифіковані за їх custom_id, із потрібними правками — наприклад, чанкуванням завеликих текстів","Перездати весь батч зі 100 документів з нуля, повністю ігноруючи те, які саме записи вже завершились успішно минулого разу","Відкинути всі провалені документи без будь-якої обробки, лишивши у вихідному наборі тільки успішні екстракції","Перевести весь процес на синхронний API назавжди, остаточно відмовившись від будь-якої пакетної обробки документів"],a:0,ex:"Збої батчу обробляють адресно: перездають лише провалені записи, ідентифіковані за custom_id, з потрібними модифікаціями — зокрема чанкуванням документів, що перевищили контекстний ліміт. Перездача всіх 100 марнує токени й час на вже успішні записи; відкидання провалених беззворотно втрачає дані; повна відмова від Batches API на користь синхронного — надмірна реакція на локальну проблему окремих документів."},
  {id:"S6Q14",s:6,d:5,q:"Ви хочете, щоб пороги перегляду базувались на надійних confidence-оцінках. Як отримати калібровані field-level confidence?",opts:["Просити модель видавати field-level confidence, а пороги калібрувати на labeled validation set","Брати самозвітований моделлю confidence як є й застосовувати його напряму без жодної калібрування","Виставити єдиний фіксований поріг 0.5 для всіх полів незалежно від їх типу й важливості","Відмовитись від confidence-оцінок узагалі й маршрутизувати кожну екстракцію на ручну перевірку"],a:0,ex:"Field-level confidence стає надійним лише після калібрування на labeled validation set, за яким і налаштовують пороги маршрутизації на рев'ю. Сирий самозвіт моделі зазвичай погано калібрований і не відображає реальної ймовірності помилки; універсальний поріг 0.5 ігнорує, що різні поля мають різну складність і ризик; ручна перевірка всього не масштабується й знецінює саму ідею порогів."},
  {id:"S6Q15",s:6,d:4,q:"Джерела мають непослідовне форматування (дати, одиниці виміру, неформальні позначення), хоча сама вихідна схема строга. Як це найкраще врахувати?",opts:["Включити правила нормалізації форматів прямо в промпт поряд зі строгою output-схемою екстракції","Послабити вихідну схему до вільного тексту, щоб вона вмістила будь-який формат із джерела як є","Ігнорувати документи з нестандартним форматуванням дат, одиниць чи неформальних позначень","Покластися на те, що строга output-схема сама приведе різнорідні формати до канонічного вигляду"],a:0,ex:"Непослідовне форматування джерел (дати, одиниці виміру, неформальні позначення) адресують, додаючи явні правила нормалізації в промпт поряд зі строгою схемою виводу — модель приводить вхід до канонічного вигляду перед заповненням полів. Послаблення схеми до вільного тексту втрачає типові гарантії й downstream-валідацію; ігнорування нестандартних документів втрачає дані; сама по собі строга схема описує форму виводу, але не нормалізує формати входу."},
  {id:"S6Q16",s:6,d:4,q:"У джерелах інколи трапляються внутрішньо суперечливі дані (напр. дві різні суми для одного значення). Як спроєктувати схему, щоб це не губилось мовчки?",opts:["Додати boolean conflict_detected і за потреби обидва значення для явного сигналу про конфлікт","Брати перше зустрінуте значення й не позначати конфлікт, аби не ускладнювати downstream-обробку","Усереднювати суперечливі значення в одне підсумкове поле, приховуючи факт розбіжності у даних","Відкидати весь документ при будь-якій внутрішній суперечності, не зберігаючи частково валідні дані"],a:0,ex:"Внутрішні суперечності джерела (напр. дві різні суми для одного значення) роблять явними через прапорець conflict_detected і збереження обох значень, щоб downstream-система бачила проблему й могла прийняти рішення. Мовчазний вибір першого значення приховує конфлікт; усереднення фабрикує число, якого немає в джерелі; відкидання всього документа втрачає всі інші валідні поля через одну розбіжність."},
  {id:"S1Q17",s:1,d:4,q:"Агент має класифікувати запит клієнта на категорії (RETURN/EXCHANGE/COMPLAINT/BILLING) для автоматичної маршрутизації. System prompt каже «відповідай лише назвою категорії», але агент інколи пише «Здається, це RETURN». Що гарантує коректний формат?",opts:["tool_use зі схемою, де requestType — enum допустимих категорій маршрутизації","Підсилений system prompt з вимогою відповідати лише одним словом — категорією","Парсинг текстової відповіді регулярками з витягуванням першої відомої категорії","Зниження temperature до нуля заради детермінованішого формату виводу моделі"],a:0,ex:"tool_use з enum-схемою — єдиний спосіб структурно гарантувати, що вивід буде рівно одним із допустимих значень (RETURN/EXCHANGE/COMPLAINT/BILLING), бо модель зобов'язана обрати елемент переліку. Підсилений промпт лише знижує частоту відхилень, але лишається ймовірнісним; regex крихкий до формулювань на кшталт «Здається, це RETURN»; нульова temperature робить вивід детермінованішим, але не обмежує словниковий запас моделі."},
  {id:"S1Q18",s:1,d:1,q:"escalate_to_human повертає помилку «no agents available». Агент має повторити спробу через 30 секунд, але зараз просто завершує діалог без вирішення. Яке архітектурне рішення правильне?",opts:["PostToolUse hook, що перехоплює помилку ескалації й планує відкладений retry","Інструкцію в system prompt зачекати хвилину й самостійно спробувати ескалацію ще раз","Збільшення timeout інструмента escalate_to_human, щоб він чекав на оператора","Дозвіл агенту вирішувати питання самостійно, коли ескалація не вдалася"],a:0,ex:"PostToolUse hook дає детерміновану runtime-логіку: перехоплює помилку «no agents available», ставить запит у чергу з затримкою 30 секунд і планує повторну спробу — це не залежить від поведінки моделі. Промпт-інструкція ймовірнісна й не здатна реалізувати реальну затримку в runtime; збільшення timeout стосується latency, а не доступності операторів; самостійне вирішення прямо суперечить вимозі ескалації кейсу."},
  {id:"S1Q19",s:1,d:5,q:"Довга сесія підтримки накопичила 8 tool-викликів, кожен повертає 20+ полів JSON. Контекст наближається до ліміту. Як діяти до переповнення?",opts:["Підсумувати завершені підзадачі й tool-результати, зберігши стан кейсу","Збільшити розмір контекстного вікна через параметри й налаштування моделі","Видаляти найстаріші повідомлення з історії незалежно від їхнього вмісту","Почати нову сесію з нуля й попросити клієнта повторити своє питання"],a:0,ex:"Вибіркове стиснення — конденсувати завершені підзадачі й verbose tool-виводи (по 20+ полів JSON кожен), зберігаючи лише активний стан кейсу та pending-пункти — підтримує безперервність діалогу без переповнення контексту. Збільшення вікна — обхід, що не усуває патерну накопичення; видалення найстаріших повідомлень може знищити критичні ранні дані клієнта; рестарт сесії руйнує UX і втрачає прогрес."},
  {id:"S1Q20",s:1,d:2,q:"lookup_order приймає orderId АБО email АБО customerId, але агент часто передає всі три поля одночасно навіть маючи лише один — це викликає помилки валідації. Найімовірніша причина?",opts:["Опис інструмента не пояснює OR-відношення — агент вважає всі поля обов'язковими","Баг у валідації бекенду, який насправді має приймати будь-яку комбінацію переданих полів","Агент неправильно парсить JSON-відповідь попереднього щойно викликаного інструмента","Низька temperature змушує модель «про всяк випадок» заповнювати всі доступні поля"],a:0,ex:"Опис інструмента — основний механізм, за яким модель розуміє контракт виклику. Нечітке OR-відношення між orderId, email і customerId (відсутність anyOf у JSON-схемі та прикладів використання) змушує модель заповнювати всі три поля «на всяк випадок», що й спричиняє помилки валідації. Виправлення опису й додавання anyOf у схему — правильний перший крок; інші варіанти не стосуються справжньої причини."},
  {id:"S2Q21",s:2,d:3,q:"Ваш кодбейс має різні конвенції: React-компоненти — functional style, API-handlers — async/await з конкретним error handling. Тест-файли розкидані по всьому проєкту поруч із кодом (напр. Button.test.tsx поруч з Button.tsx). Ви хочете, щоб Claude автоматично застосовував правильні конвенції при генерації — незалежно від місця файлу. Найбільш підтримуваний підхід?",opts:["Створити файли правил у .claude/rules/ з YAML frontmatter і glob-патернами для умовного завантаження по шляху","Зібрати всі конвенції в кореневому CLAUDE.md під заголовками й покластися на Claude самостійно обрати потрібну секцію","Створити окремі skills у .claude/skills/ для кожного типу коду, описавши відповідні конвенції у файлі SKILL.md","Покласти окремий CLAUDE.md у кожну піддиректорію проєкту з конвенціями, релевантними саме для цієї зони коду"],a:0,ex:"Файли правил у .claude/rules/ з glob-патернами у frontmatter (напр. **/*.test.tsx) дозволяють автоматично застосовувати конвенції за шляхом файлу незалежно від директорії — це ідеально для тест-файлів, розкиданих по всьому проєкту поруч із кодом. Консолідація в CLAUDE.md покладається на інференцію моделі, а не на точне зіставлення шляху; skills потребують ручного виклику; окремі CLAUDE.md по директоріях не вирішують проблему файлів одного типу, розкиданих по всій кодбейсі."},
  {id:"S2Q17",s:2,d:4,q:"Команда хоче, щоб Claude Code генерував тести у специфічному стилі (describe/it блоки, конкретні assertion-бібліотеки, стиль коментарів). Опис у CLAUDE.md не дає стабільного результату. Що найефективніше?",opts:["Додати у CLAUDE.md 2–3 конкретні приклади тестів у бажаному стилі як few-shot для надійного закріплення цього патерну в моделі","Детальніше описати потрібний стиль прозою, перелічивши describe/it блоки та конкретні assertion-бібліотеки команди","Підвищити temperature заради більшої варіативності генерації й відбирати найкращий результат серед кількох спроб","Завжди давати завдання генерації тестів в окремій ізольованій сесії, без попереднього контексту цього проєкту"],a:0,ex:"Few-shot приклади — найефективніший спосіб закріпити конкретний стиль тестів: модель узагальнює патерн із демонстрацій вхід/вихід надійніше, ніж слідує абстрактному опису. Детальніша проза з переліком конвенцій допомагає, але дає менш стабільний результат; підвищення temperature додає варіативність, а не консистентність; ізольована сесія без контексту лише ускладнює задачу, не вирішуючи її."},
  {id:"S2Q18",s:2,d:5,q:"Під час рефакторингу 30+ файлів контекст сесії заповнюється і Claude починає «забувати» зміни, внесені на початку — посилається на старі назви функцій. Яка стратегія найефективніша?",opts:["Вести structured changelog-файл у репозиторії: після кожного файлу фіксувати зміни як джерело правди","Перезапускати сесію Claude Code після кожних п'яти оброблених файлів, починаючи контекст щоразу з нуля","Збільшити параметр max_tokens, щоб відповіді ставали довшими й уміщали більше деталей про внесені зміни","Просити Claude через system prompt «запам'ятати» всі зроблені зміни й тримати їх в активному контексті"],a:0,ex:"Structured changelog — зовнішній persistent-файл у репозиторії, який агент читає як актуальне джерело правди про вже внесені зміни незалежно від стану контекст-вікна. Перезапуск сесій щоразу втрачає накопичений прогрес; max_tokens стосується довжини виводу, а не розміру контекст-вікна; покладання на «запам'ятовування» в контексті ненадійне, бо ранні зміни витісняються при переповненні."},
  {id:"S2Q19",s:2,d:1,q:"Задача потребує змін у 15 взаємопов'язаних файлах: API, адаптери, тести, документація. Яка стратегія декомпозиції оптимальна?",opts:["Prompt chaining: спершу побудувати план і граф залежностей, потім вносити покрокові зміни з verification-чекпоінтами між кроками","Паралельний запуск 15 повністю незалежних агентів — по одному окремому агенту на кожен із взаємопов'язаних файлів","Один великий промпт із повним і детальним описом усіх 15 необхідних змін, що виконуються разом за раз","Починати зміни у довільному порядку без попереднього аналізу залежностей і виправляти конфлікти між файлами по факту"],a:0,ex:"Взаємопов'язані зміни через кілька файлів вимагають координованого підходу через prompt chaining: спочатку граф залежностей, потім зміни у правильному порядку з verification-чекпоінтами між кроками. Паралельні агенти без координації створять конфлікти у взаємозалежних файлах; один гігантський промпт спричинить attention dilution; довільний порядок порушить залежності між API, адаптерами, тестами й документацією."},
  {id:"S2Q20",s:2,d:3,q:"Команда хоче, щоб Claude Code автоматично дотримувався naming conventions, структури директорій і правил імпортів у всіх сесіях. Де і як налаштувати?",opts:["Project-level CLAUDE.md з конкретними прикладами conventions — автоматично завантажується у кожній сесії","Повторювати всі naming conventions, структуру директорій і правила імпортів вручну у тексті кожного промпта","Зберігати правила у файлі .eslintrc і розраховувати, що Claude самостійно прочитає й застосує їх автоматично","Налаштовувати ці conventions у користувацькому ~/.claude/CLAUDE.md, спільному одразу для всіх проєктів команди"],a:0,ex:"Project-level CLAUDE.md — правильне місце для командних conventions: він версіонується разом із кодом у git і автоматично завантажується у кожну сесію для всіх розробників. Мануальне повторення в кожному промпті ненадійне й дороге за токенами; .eslintrc Claude не читає автоматично без явного запиту; user-level ~/.claude/CLAUDE.md не шериться через version control і застосовується лише до одного користувача."},
  {id:"S1Q21",s:1,d:1,q:"Агент ескалує складний кейс до людського оператора, але той не має доступу до попередньої переписки. Яку інформацію зобов'язаний підготувати агент при ескалації?",opts:["Структурований handoff: ID клієнта, корінна причина звернення, уже спробовані дії та рекомендована наступна дія","Лише посилання на тікет — оператор сам знайде потрібний йому контекст у внутрішній системі підтримки","Повний дослівний текст усього діалогу з клієнтом, скопійований у поле коментаря самого тікета","Нічого окремо не готувати — оператор сам розпитає клієнта про суть та деталі його проблеми"],a:0,ex:"Structured handoff summary — ID клієнта, корінна причина звернення, уже спробовані дії та рекомендована наступна дія — дозволяє оператору відразу продуктивно діяти, не перечитуючи весь чат. Саме посилання на тікет не гарантує наявності контексту; повний дослівний текст діалогу перекладає на оператора зайве читання довгої переписки; відсутність передачі змушує клієнта повторювати все спочатку й нівелює сенс ескалації."},
  {id:"S3Q17",s:3,d:4,q:"Synthesis-агент повертає фінальний звіт у вільному форматі — щоразу різна структура, різні назви секцій. Downstream-системи не можуть надійно парсити вивід. Як виправити?",opts:["Визначити JSON-схему звіту і виставити її як tool_use — synthesis зобов'язаний заповнити поля","Додати в промпт synthesis-агента деталізований текстовий шаблон бажаної структури звіту з прикладами","Парсити вільний вивід synthesis-агента NLP-постпроцесингом на бекенді, виокремлюючи потрібні секції","Просити synthesis-агента додавати окремий JSON-блок у кінці після основного тексту звіту"],a:0,ex:"tool_use з JSON-схемою дає структурно гарантований вивід: synthesis зобов'язаний заповнити визначені схемою поля у фіксованій структурі, тож downstream надійно парсить результат. Деталізований шаблон у промпті знижує варіативність, але не гарантує дотримання схеми. NLP-постпроцесинг вільного тексту — крихка обробка, чутлива до змін формулювань. Окремий JSON-блок у кінці все одно лишається вільним текстом, який треба знайти й розпарсити вручну."},
  {id:"S3Q18",s:3,d:2,q:"web-search субагент має єдиний інструмент search(query), що повертає сирий HTML. Synthesis-агент витрачає багато токенів на парсинг. Як покращити дизайн інструментів?",opts:["Розбити на purpose-specific інструменти: search_web, fetch_page (clean text) і extract_facts","Дати synthesis-агенту прямий доступ до search(query), щоб він сам шукав і парсив потрібне з HTML","Збільшити max_tokens synthesis-агента, щоб він міг помістити й обробити весь сирий HTML за раз","Кешувати HTML-відповіді й парсити їх окремим бекенд-сервісом ще до передачі synthesis-агенту"],a:0,ex:"Purpose-specific інструменти з чіткими output-контрактами усувають парсинг на стороні downstream: search_web повертає структуровані результати, fetch_page — чистий текст, extract_facts — ключові факти з джерела. Прямий доступ synthesis-агента до сирого search() порушує separation of concerns і не знімає тягар парсингу. Збільшення max_tokens не вирішує марнування токенів на HTML. Окремий кеш-сервіс — валідний патерн оптимізації, але питання саме про дизайн інструментів."},
  {id:"S3Q19",s:3,d:1,q:"Деякі research-запити прості (один аспект, одне джерело), але coordinator завжди запускає повний пайплайн усіх субагентів. Як проєктувати coordinator для адаптивності?",opts:["Coordinator першим кроком аналізує складність запиту й динамічно обирає мінімальний набір субагентів","Зробити всіх субагентів суттєво швидшими, щоб повний пайплайн перестав бути проблемою для простих запитів","Замінити coordinator лінійним ланцюгом і запускати всі кроки строго послідовно один за одним","Додати word-threshold: короткі за кількістю слів запити направляти лише до web-search субагента"],a:0,ex:"Адаптивна декомпозиція на основі аналізу складності — правильний патерн: coordinator оцінює запит і динамічно обирає мінімально необхідний набір субагентів, бо різні запити потребують різного. Прискорення всіх субагентів не усуває марнування токенів і кроків для простих запитів. Лінійний ланцюг не дозволяє пропускати непотрібні кроки. Word-threshold за довжиною — надто груба евристика, що не відображає реальної складності запиту."},
  {id:"S3Q20",s:3,d:5,q:"Coordinator запускає research-сесії щоденно. Нові запити часто перекривають вже досліджені теми, але кожна сесія починається з нуля. Як накопичувати знання між сесіями?",opts:["Persistent knowledge store зі структурованими знахідками й датами, що його читає coordinator","Зберігати повні сирі логи кожної сесії й цілком передавати їх у контекст наступного запуску","Збільшити частоту research-запусків, щоб між сесіями лишалось менше тематичного перекривання","Просити користувача вручну вказувати вже досліджені теми перед кожним новим запуском сесії"],a:0,ex:"Persistent knowledge store (файл або БД) зі структурованими знахідками й датами дозволяє coordinator'у на початку сесії прочитати накопичене знання й передати релевантний контекст субагентам, ефективно інтегруючи минулі дослідження без переповнення вікна. Повні сирі логи кожної сесії занадто об'ємні й швидко переповнять контекст. Частіші запуски не усувають перекривання тем. Ручне вказування досліджених тем перекладає роботу на людину й не масштабується."},
  {id:"S3Q21",s:3,d:4,q:"Synthesis-агент витягує metadata з документа, але поле «рік публікації» стабільно повертає помилку валідації — поле обов'язкове в схемі, але в усіх вхідних документах ця інформація відсутня. Чи допоможе retry?",opts:["Ні — retry безсилий, коли інформація відсутня в джерелі; поле «рік публікації» треба зробити nullable","Так — при достатній кількості повторних спроб модель зрештою «знайде» потрібне значення десь у тексті","Так — якщо передати у follow-up детальніше пояснення помилки валідації, модель заповнить поле коректно","Так — якщо збільшити max_tokens, модель проаналізує документ ретельніше й видобуде відсутній рік"],a:0,ex:"Retry ефективний для format/structural помилок (неправильний тип, погане форматування, невалідна структура), але коли інформація фізично відсутня в усіх вхідних документах — жодна кількість спроб її не створить. Правильне рішення — зробити обов'язкове поле nullable, щоб модель повертала null замість фабрикації неіснуючих даних. Решта варіантів хибно припускають, що повтори, докладніше пояснення помилки чи більший max_tokens здатні видобути дані, яких у джерелі немає; це лише провокує галюцинації."},
  {id:"S4Q17",s:4,d:3,q:"Інженер хоче зрозуміти, як legacy authentication модуль взаємодіє з 12 залежними сервісами. Яка послідовність built-in інструментів найефективніша?",opts:["Grep для точок входу auth, Read ключових файлів, Glob для залежних модулів, Read для трасування","Прочитати всі 12 файлів сервісів повністю наперед, щоб одразу мати цілісну картину взаємодій","Запустити grep -r через Bash вручну і передати сирий вивід Claude для подальшого аналізу зв'язків","Glob для списку всіх файлів проєкту, потім Read кожного файлу послідовно по одному аж до кінця"],a:0,ex:"Інкрементальний підхід ефективно використовує контекст: спершу пошук точок входу, потім читання ключових файлів, виявлення залежних модулів і трасування. Читання всіх файлів наперед з'їдає контекст без цілеспрямованості; ручний grep через Bash дублює вбудований пошук; перелік усіх файлів із послідовним читанням переповнює контекст."},
  {id:"S4Q18",s:4,d:4,q:"Claude генерує технічну документацію для функцій, але вона або надто коротка (парафраз сигнатури), або надто довга (пояснює очевидне). Як отримати стабільно корисну документацію?",opts:["Дати 2–3 приклади добре задокументованих функцій із того самого кодбейсу як few-shot","Просити Claude бути стислим, але повним, додаючи це формулювання у кожен окремий промпт","Генерувати документацію двічі поспіль і щоразу вручну обирати суб'єктивно кращу з версій","Встановити жорсткий точний ліміт довжини в промпті, наприклад рівно три речення на функцію"],a:0,ex:"Few-shot приклади з того самого кодбейсу показують правильний рівень деталізації і стиль команди. Інструкція бути стислим, але повним надто неоднозначна; подвійна генерація дорога й суб'єктивна; жорсткий ліміт слів обмежує обсяг, але не передає бажану якість документації."},
  {id:"S4Q19",s:4,d:5,q:"Після 2 годин дослідження кодбейсу Claude починає давати менш точні відповіді — посилається на «типові патерни» замість конкретних класів, знайдених раніше. Симптом і причина?",opts:["Переповнення контексту: ранні специфічні знахідки витісняються і модель узагальнює","Модель поступово втомлюється від надто тривалих сесій і просто потребує перезапуску","Кодбейс має завеликий розмір і взагалі непосильний для будь-якої наявної AI-моделі","Причина у виборі Read замість Grep для пошуку потрібних класів по всьому кодбейсу"],a:0,ex:"У довгих сесіях ранні знахідки витісняються новим вмістом, і модель зісковзує на узагальнення замість конкретики. Рішення — scratchpad-файл із ключовими знахідками, на який спираються в наступних питаннях. Моделі не втомлюються; проблема не в розмірі кодбейсу; вибір між пошуком і читанням не стосується причини."},
  {id:"S4Q20",s:4,d:1,q:"Ви розслідуєте performance-регресію з двома рівно-вірогідними гіпотезами: DB-запити або кешування. Обидві потребують окремого глибокого аналізу від спільного baseline. Що використати?",opts:["fork_session від спільного baseline: одна незалежна гілка для DB-запитів, інша для кешування, обидві паралельно","Використати --resume однієї сесії і поступово перемикатися між двома гіпотезами по черзі вручну","Відкрити дві повністю незалежні нові сесії, кожна без жодного спільного базового контексту аналізу","Працювати в одній сесії суто послідовно: спершу повністю розібрати DB, а потім перейти до кешу"],a:0,ex:"fork_session створює незалежні гілки від спільного baseline-аналізу — ідеально для паралельного дослідження двох рівноймовірних гіпотез без дублювання базової роботи. Resume однієї сесії змішає гілки; дві незалежні сесії дублюють базовий аналіз; послідовна робота вдвічі довша без жодних переваг."},
  {id:"S4Q21",s:4,d:3,q:"Ваш skill для генерації boilerplate запускається командою /gen, але розробники забувають передати обов'язковий аргумент (назву компонента) і skill падає з помилкою. Який механізм Claude Code вирішує це?",opts:["argument-hint у frontmatter SKILL.md підкаже розробнику ввести потрібний параметр","Додати власну перевірку в тіло skill і виводити зрозуміле повідомлення про брак аргументу","Зробити назву компонента обов'язковим полем у системному промпті, що задає контекст усій сесії","Прибрати можливість запускати skill без аргументів, обмеживши його через поле allowed-tools"],a:0,ex:"argument-hint у frontmatter SKILL.md — стандартний механізм Claude Code, що запитує обов'язкові параметри при виклику skill без аргументів. Власна перевірка в тілі працює, але дублює вбудований механізм; системний промпт не зарадить відсутньому аргументу; allowed-tools обмежує інструменти, а не параметри."},
  {id:"S5Q17",s:5,d:3,q:"CI-пайплайн запускає Claude Code для аналізу PR, але Claude не має доступу до корпоративних стандартів кодування. Claude Code повертає generic рекомендації замість специфічних для команди. Як виправити?",opts:["Зберігати стандарти кодування в CLAUDE.md репозиторію — автоматично завантажується у CI","Передавати весь набір стандартів через довгий --system-prompt аргумент у кожному CI-виклику","Зберігати стандарти у зовнішній корпоративній вікі й просити розробників передавати URL","Хардкодити повний текст стандартів прямо у CI-скрипті через змінну оточення"],a:0,ex:"Project-level CLAUDE.md автоматично надає Claude Code контекст команди: він версіонується в git разом із кодом і підхоплюється у CI-сесії без додаткових аргументів. Передача стандартів через довгий --system-prompt у кожному виклику некерована й дорога в підтримці. Зовнішня вікі до моделі не доходить без явного кроку читання URL. Хардкод у CI-скрипті через env var обходить призначений механізм і дублює конфігурацію поза репозиторієм коду."},
  {id:"S5Q18",s:5,d:4,q:"CI code review флагає будь-яке використання innerHTML або eval() як проблему, навіть у перевірених утилітах. False positive rate критично підриває довіру команди. Як уточнити критерій?",opts:["Флагати innerHTML/eval лише коли вхідні дані надходять із зовнішнього джерела без санітизації","Повністю вимкнути перевірку innerHTML і eval, щоб одразу прибрати всі хибні спрацювання рев'ю","Додати правило перевіряти лише критичні security-проблеми й підняти загальний поріг знахідок","Вручну вносити всі дозволені виклики у спільний whitelist перед кожним запуском рев'ю PR команди"],a:0,ex:"Конкретний категоріальний критерій — небезпека innerHTML/eval залежить від того, чи дані приходять із зовнішнього джерела без санітизації — різко знижує false positives, зберігаючи захист від реальних вразливостей. Повне вимкнення перевірки усуває й справжні проблеми. Загальне підняття порога знижує точність для інших категорій теж. Ручний whitelist вимагає постійного обслуговування й не масштабується на кодбазу, що росте."},
  {id:"S5Q19",s:5,d:5,q:"PR зростав поступово: 6 комітів за 3 дні. Claude переглядає лише diff останнього коміту, але пропускає проблеми від взаємодії ранніх і пізніх змін. Як виправити?",opts:["Передавати у контекст рев'ю повний PR diff — усі шість комітів від base branch разом за один прохід","Запускати окреме рев'ю на кожен з шести комітів і потім якось агрегувати отримані результати","Збільшити max_tokens виклику, щоб умістити більше коду й історії змін в одному проході","Просити Claude самостійно запитувати попередні diff'и в репозиторії вже за потреби під час рев'ю"],a:0,ex:"Крос-коміт проблеми виявляються тільки при аналізі повного PR diff — взаємодія ранніх і пізніх змін невидима з diff лише останнього коміту. Окремі рев'ю на кожен коміт теж не побачать взаємодію між ними, бо кожне дивиться на свій ізольований шматок. Параметр max_tokens стосується довжини виводу, а не обсягу вхідного контексту. Claude не може самостійно ініціювати запит попередніх diff'ів без наданого інструмента й команди."},
  {id:"S5Q20",s:5,d:1,q:"Ви хочете паралельно виконати security review, performance review і correctness review великого PR. Яка архітектура найефективніша?",opts:["Три незалежні Claude-інстанси паралельно, кожен спеціалізований на одному вимірі","Один промпт із проханням перевірити всі три виміри рев'ю одночасно в межах одного проходу","Послідовно security, потім performance, потім correctness у межах однієї спільної сесії","Один агент із трьома різними значеннями temperature, по одному на кожен вимір рев'ю"],a:0,ex:"Паралельні спеціалізовані інстанси — по одному на security, performance і correctness, кожен зі своїм промптом і критеріями — дають і швидкість, і глибину кожного домену. Один промпт на всі три виміри спричиняє attention dilution: модель розпорошує увагу й гірше покриває кожен аспект. Послідовне виконання в одній сесії втричі повільніше без виграшу в якості. Різні temperature не змінюють здатність аналізувати різні виміри й не дають спеціалізації."},
  {id:"S5Q21",s:5,d:1,q:"Після автоматичного code review Claude звітує про кілька проблем, але через постійні false positives в одній з категорій (стиль) розробники ігнорують весь вивід — навіть справжні баги. Що зробити в першу чергу?",opts:["Тимчасово вимкнути категорію стилю з високим рівнем false positives, паралельно доопрацьовуючи її критерії","Залишити все як є й просто додати в CLAUDE.md пояснення, що не всі знахідки рев'ю однаково критичні","Знизити загальну кількість знахідок наполовину незалежно від конкретної проблемної категорії","Перейти з автоматичного code review виключно на повністю ручне рев'ю силами самих розробників"],a:0,ex:"Висока кількість false positives в одній категорії (стилі) отруює довіру до всього виводу рев'ю — розробники починають ігнорувати навіть справжні баги. Тимчасове вимкнення проблемної категорії відновлює корисність точних категорій і дає час на якісне доопрацювання критеріїв. Пояснення в CLAUDE.md не усуває технічну причину спрацювань. Сліпе скорочення знахідок наполовину ріже й важливі знахідки. Перехід на суто ручне рев'ю взагалі скасовує переваги автоматизації."},
  {id:"S6Q17",s:6,d:4,q:"Документи мають ієрархічну структуру: invoice → line_items[] → adjustments[]. Поточна плоска схема втрачає ієрархію. Як правильно спроєктувати схему?",opts:["Вкладені об'єкти: Invoice містить масив LineItem, а кожен LineItem — масив об'єктів Adjustment","Зберігати поля плоско з prefix-номерами (item1_price, item1_qty) для кожного рядка документа","Витягувати лише верхній рівень (invoice total), ігноруючи line items та вкладені в них adjustments","Зберігати весь масив line items як серіалізований JSON-рядок усередині одного рядкового поля схеми"],a:0,ex:"Вкладені об'єкти точно відображають ієрархічну природу даних (invoice → line_items[] → adjustments[]) і дозволяють downstream-системам коректно обробляти довільну кількість елементів на кожному рівні. Плоска схема з prefix-номерами негнучка й ламається при змінній кількості items; витягування лише верхнього рівня втрачає деталізацію рядків; JSON-рядок усередині рядкового поля унеможливлює типізовану валідацію й обробку вкладених даних."},
  {id:"S6Q18",s:6,d:5,q:"Система показує 95% точності на тестовому наборі, але клієнти скаржаться на помилки саме в рахунках від нових постачальників. Яка причина і рішення?",opts:["Тестовий набір не має документів нових постачальників; потрібна стратифікована оцінка","95% — цілком достатня точність, а реальна проблема лише в завищених очікуваннях клієнтів","Підняти поріг confidence для всіх екстракцій, і тоді помилки в нових рахунках просто зникнуть","Перейти на інший LLM із вищою загальною точністю, не розбираючись у причині цих помилок"],a:0,ex:"Агрегатна метрика маскує погану продуктивність на нових форматах. Стратифікована оцінка (за постачальником, форматом, часовим вікном) і регулярне поповнення тестового набору продакшен-даними виявляє реальні слабкі місця. Ігнорування проблеми не зарадить; підняття порогу збільшить кількість відхилених, а не точність; зміна LLM без розуміння причини — лише ризик."},
  {id:"S6Q19",s:6,d:1,q:"Великий батч документів потребує: (1) класифікації типу, (2) вибору схеми, (3) екстракції, (4) валідації. Яка архітектура оркестрації оптимальна?",opts:["Prompt chaining: кожен крок передає вивід наступному, а валідація запускає retry лише для невалідних","Один великий промпт, що виконує всі чотири кроки (класифікація, схема, екстракція, валідація) за один прохід","Чотири незалежні агенти без координатора, кожен з яких самостійно опрацьовує весь батч документів цілком","Паралельний запуск усіх чотирьох кроків одночасно для кожного документа задля максимальної швидкості"],a:0,ex:"Prompt chaining — правильний патерн для передбачуваних послідовних кроків із явними залежностями: вивід класифікації (крок 1) визначає вибір схеми (крок 2), тож паралелізм між кроками неможливий. Окремий крок валідації запускає retry тільки для невалідних результатів. Один промпт для всіх чотирьох кроків спричиняє attention dilution; незалежні агенти без координатора не можуть передавати контекст між кроками, що ламає ланцюг залежностей."},
  {id:"S6Q20",s:6,d:2,q:"Система має два інструменти: extract_invoice і extract_contract. Обидва приймають raw_text. Агент часто викликає не той інструмент — invoice для контрактів і навпаки. Причина і рішення?",opts:["Описи не розрізняють типи документів: додати у description ключові ознаки кожного типу та приклади trigger-ситуацій","Об'єднати обидва в один extract_document(type, raw_text) і покласти на агента визначення типу документа","Форсувати tool_choice: auto, лишивши моделі вибір потрібного інструмента взагалі без зміни описів","Додати окремий preprocessing-крок, що класифікує документ і викликає потрібний інструмент замість агента"],a:0,ex:"Якість вибору інструмента пропорційна якості його опису. Додавання ключових ознак типу (invoice: line items, payment terms; contract: parties, obligations, duration) і прикладів trigger-ситуацій у description усуває неоднозначність вибору між схожими інструментами. Об'єднання в один інструмент лише переносить ту саму задачу класифікації всередину агента; tool_choice: auto — це фактично поточний стан, що й не вирішує проблему; зовнішній preprocessing-класифікатор може бути валідним патерном, але питання стосується саме описів інструментів."},
];

export function getQuestionsByDomain(domainId: number): Question[] {
  return QB.filter(q => q.d === domainId);
}

export function getQuestionsByScenario(scenId: number): Question[] {
  return QB.filter(q => q.s === scenId);
}

export const PASS_SCALED = 720;
export const TOTAL_EXAM_QUESTIONS = 60;
export const EXAM_DURATION_SEC = 120 * 60;
